-- CARDIOLOGY (8 posts) - Dr. Emily Carter (1-2), Dr. James Wilson (3-4), Dr. Michael Roberts (5), Dr. Sarah Mitchell (6), Dr. David Chen (7-8)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(1, 'Understanding Heart Disease: Prevention and Management', 'Learn about heart disease prevention and management strategies. Discover the latest advances in heart disease prevention, diagnosis, and treatment options.', '<strong>Understanding Heart Disease: A Comprehensive Guide</strong>\n\nHeart disease remains the leading cause of death worldwide, accounting for approximately 17.9 million deaths annually. This comprehensive guide explores the latest advances in heart disease prevention, diagnosis, and treatment options.\n\n<strong>What is Heart Disease?</strong>\nHeart disease refers to several types of heart conditions. The most common type is coronary artery disease (CAD), which affects blood flow to the heart. Other types include arrhythmias, heart failure, and valvular heart disease.\n\n<strong>Key Risk Factors:</strong>\n• <strong>High Blood Pressure</strong>: The silent killer that damages arteries over time\n• <strong>High Cholesterol</strong>: Leads to plaque buildup in arteries\n• <strong>Smoking</strong>: Damages blood vessels and reduces oxygen in blood\n• <strong>Diabetes</strong>: Increases risk of heart disease by 2-4 times\n• <strong>Obesity</strong>: Extra weight strains the heart\n• <strong>Family History</strong>: Genetic predisposition plays a significant role\n• <strong>Age</strong>: Risk increases with age\n\n<strong>Prevention Strategies:</strong>\n1. <strong>Regular Exercise</strong>: At least 150 minutes of moderate activity per week\n2. <strong>Healthy Diet</strong>: Mediterranean diet rich in fruits, vegetables, whole grains\n3. <strong>Stress Management</strong>: Meditation, yoga, adequate sleep\n4. <strong>Regular Check-ups</strong>: Monitor blood pressure, cholesterol, blood sugar\n\n<strong>Treatment Options:</strong>\n• Lifestyle modifications\n• Medications (statins, beta-blockers, ACE inhibitors)\n• Surgical procedures (angioplasty, bypass surgery)\n\n<strong>Living with Heart Disease:</strong>\nManaging heart disease is a lifelong journey. Regular follow-ups with your cardiologist, medication adherence, and lifestyle modifications are key to living a full and active life.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/nThnVdnm0So/maxresdefault.jpg', 'https://www.youtube.com/watch?v=nThnVdnm0So', '2024-01-15 10:00:00', '8 min read', 0, 0, 0, true, true, 'understanding-heart-disease', NOW(), NOW()),

(2, '5 Signs You Should See a Cardiologist', 'Know the warning signs that require a cardiologist visit. Early detection can save lives.', '<strong>5 Signs You Should See a Cardiologist Immediately</strong>\n\nHeart disease is often called the "silent killer" because symptoms can be subtle. Early detection can save lives. Here are 5 critical signs that require immediate attention from a cardiologist.\n\n<strong>1. Chest Pain or Discomfort</strong>\nChest pain is the most common symptom of heart problems. It may feel like pressure, squeezing, fullness, or pain in the center of the chest. Don''t ignore any chest discomfort, especially if it lasts more than a few minutes.\n\n<strong>2. Shortness of Breath</strong>\nIf you find yourself getting winded from activities that used to be easy, it could be a sign of heart issues. Shortness of breath can indicate heart failure or coronary artery disease.\n\n<strong>3. Palpitations</strong>\nIrregular heartbeats or a feeling that your heart is racing could indicate arrhythmia or other heart conditions. While occasional palpitations are normal, frequent ones need evaluation.\n\n<strong>4. Dizziness or Lightheadedness</strong>\nFrequent dizziness could be a sign of low blood pressure or heart rhythm problems. If you experience dizziness along with chest pain or shortness of breath, seek immediate medical attention.\n\n<strong>5. Swelling in Legs</strong>\nSwelling in your legs, ankles, or feet could be a sign of heart failure or poor circulation. This symptom often indicates that your heart is not pumping blood effectively.\n\n<strong>When to See a Doctor:</strong>\nIf you experience any of these symptoms, especially if they occur together, schedule an appointment with a cardiologist immediately. Early intervention can save lives.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/zZY4sG_-cmo/maxresdefault.jpg', 'https://www.youtube.com/watch?v=zZY4sG_-cmo', '2024-01-20 10:00:00', '6 min read', 0, 0, 0, false, true, 'signs-to-see-cardiologist', NOW(), NOW()),

(3, 'Heart Surgery: What to Expect', 'A complete guide to heart surgery preparation and recovery. Learn what to expect before, during, and after surgery.', '<strong>Heart Surgery: A Complete Guide to What to Expect</strong>\n\nHeart surgery can be daunting, but with the right preparation and knowledge, you can approach it with confidence. This comprehensive guide walks you through every step of the journey.\n\n<strong>Before Surgery:</strong>\n• Complete all pre-operative tests (blood work, ECG, chest X-ray)\n• Discuss all medications with your surgeon\n• Arrange for help during recovery\n• Prepare your home for recovery\n\n<strong>What to Expect:</strong>\n• Hospital stay: 3-7 days\n• Recovery time: 6-12 weeks\n• Follow-up visits: Regular\n\n<strong>Types of Heart Surgery:</strong>\n1. <strong>Coronary Artery Bypass Grafting (CABG)</strong> – Creates new pathways for blood to flow to the heart\n2. <strong>Valve Repair or Replacement</strong> – Replacing damaged heart valves\n3. <strong>Heart Transplant</strong> – For end-stage heart failure\n\n<strong>Recovery Timeline:</strong>\n• Week 1-2: Hospital stay, initial recovery\n• Week 3-6: Gradual return to daily activities\n• Week 6-12: Return to work\n• 3-6 months: Full recovery, cardiac rehabilitation\n\n<strong>Tips for Successful Recovery:</strong>\n• Follow all post-surgery instructions carefully\n• Attend cardiac rehabilitation sessions\n• Take all medications as prescribed\n• Listen to your body and don''t overexert\n• Maintain a heart-healthy diet\n• Stay positive and patient with your recovery\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/26.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/GWq25TkvVOY/maxresdefault.jpg', 'https://www.youtube.com/watch?v=GWq25TkvVOY', '2024-01-25 10:00:00', '10 min read', 0, 0, 0, true, true, 'heart-surgery-guide', NOW(), NOW()),

(4, 'Managing High Blood Pressure Naturally', 'Natural strategies to lower blood pressure without medication. Learn lifestyle changes that work.', '<strong>Managing High Blood Pressure Naturally: A Comprehensive Guide</strong>\n\nHigh blood pressure (hypertension) affects nearly half of all adults worldwide. It''s often called the "silent killer" because it usually has no symptoms but can lead to serious health problems.\n\n<strong>Natural Ways to Lower Blood Pressure:</strong>\n\n<strong>Dietary Changes:</strong>\n• <strong>Reduce Sodium</strong>: Aim for less than 2,300mg per day\n• <strong>Increase Potassium</strong>: Eat bananas, sweet potatoes, spinach\n• <strong>DASH Diet</strong>: Rich in fruits, vegetables, whole grains\n• <strong>Limit Alcohol</strong>: No more than 1-2 drinks per day\n\n<strong>Regular Exercise:</strong>\n• Aerobic exercise: 30 minutes, 5 days per week\n• Strength training: 2-3 times per week\n• Yoga and stretching: Helps reduce stress\n\n<strong>Stress Management:</strong>\n• Meditation and deep breathing\n• Adequate sleep (7-8 hours)\n• Time in nature\n• Hobbies and relaxation\n\n<strong>Lifestyle Changes:</strong>\n• Maintain healthy weight\n• Quit smoking\n• Limit caffeine\n• Monitor blood pressure at home\n\n<strong>When to See a Doctor:</strong>\nWhile natural methods can help, some people need medication. Always consult with your healthcare provider before making significant changes to your treatment plan.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/26.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/J4UelDe-lUM/maxresdefault.jpg', 'https://www.youtube.com/watch?v=J4UelDe-lUM', '2024-02-01 10:00:00', '7 min read', 0, 0, 0, false, true, 'manage-high-blood-pressure', NOW(), NOW()),

(5, 'Understanding Cholesterol: Good vs Bad', 'Learn the difference between good and bad cholesterol. Understand how to improve your cholesterol levels.', '<strong>Understanding Cholesterol: Good vs Bad – A Complete Guide</strong>\n\nCholesterol is a waxy, fat-like substance found in your blood. Your body needs cholesterol to build healthy cells, but high levels can increase your risk of heart disease.\n\n<strong>Good Cholesterol (HDL):</strong>\nHDL (High-Density Lipoprotein) is called "good" cholesterol because it carries cholesterol from other parts of your body back to your liver. Your liver then removes the cholesterol from your body.\n\n<strong>Bad Cholesterol (LDL):</strong>\nLDL (Low-Density Lipoprotein) is called "bad" cholesterol because it can build up in the walls of your arteries, leading to plaque formation and heart disease.\n\n<strong>How to Improve Your Cholesterol:</strong>\n\n<strong>Diet Changes:</strong>\n• Eat more soluble fiber (oats, beans, fruits)\n• Choose healthy fats (olive oil, avocados, nuts)\n• Avoid trans fats and saturated fats\n• Eat fatty fish (salmon, mackerel) twice a week\n\n<strong>Exercise:</strong>\n• 30 minutes of moderate exercise daily\n• Brisk walking, jogging, swimming\n• Regular physical activity raises HDL\n\n<strong>Lifestyle:</strong>\n• Quit smoking\n• Maintain healthy weight\n• Limit alcohol intake\n• Manage stress\n\n<strong>When to Get Tested:</strong>\nAdults should have their cholesterol checked every 4-6 years. If you have risk factors, you may need more frequent testing.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. Michael Roberts', 'https://randomuser.me/api/portraits/men/27.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/JE2nbiY4HTc/maxresdefault.jpg', 'https://www.youtube.com/watch?v=JE2nbiY4HTc', '2024-02-05 10:00:00', '6 min read', 0, 0, 0, false, true, 'understanding-cholesterol', NOW(), NOW()),

(6, 'Heart Attack Prevention: A Complete Guide', 'Learn how to prevent heart attacks with lifestyle changes and medical management.', '<strong>Heart Attack Prevention: A Comprehensive Guide</strong>\n\nA heart attack (myocardial infarction) occurs when blood flow to the heart is blocked, usually by a blood clot. Heart attacks are medical emergencies that require immediate attention.\n\n<strong>Warning Signs of a Heart Attack:</strong>\n• Chest pain or discomfort\n• Pain radiating to arm, jaw, or back\n• Shortness of breath\n• Nausea or vomiting\n• Cold sweat\n• Dizziness or lightheadedness\n\n<strong>Prevention Strategies:</strong>\n\n<strong>Lifestyle Modifications:</strong>\n• <strong>Exercise Regularly</strong>: 150 minutes of moderate activity per week\n• <strong>Healthy Diet</strong>: Mediterranean or DASH diet\n• <strong>Maintain Healthy Weight</strong>: BMI between 18.5-24.9\n• <strong>Quit Smoking</strong>: Reduces risk by 50% within 1 year\n• <strong>Limit Alcohol</strong>: No more than 1-2 drinks daily\n\n<strong>Medical Management:</strong>\n• Monitor blood pressure regularly\n• Control cholesterol levels\n• Manage diabetes if applicable\n• Take medications as prescribed\n\n<strong>Stress Management:</strong>\n• Practice relaxation techniques\n• Get adequate sleep (7-8 hours)\n• Maintain work-life balance\n\n<strong>When to Seek Emergency Care:</strong>\nIf you experience any warning signs, call emergency services immediately. Every minute counts during a heart attack.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. Sarah Mitchell', 'https://randomuser.me/api/portraits/women/2.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/0MxoazXH74g/maxresdefault.jpg', 'https://www.youtube.com/watch?v=0MxoazXH74g', '2024-02-10 10:00:00', '9 min read', 0, 0, 0, false, true, 'heart-attack-prevention', NOW(), NOW()),

(7, 'Living with Heart Failure: Tips and Support', 'Practical tips and support for living with heart failure. Learn how to manage symptoms and improve quality of life.', '<strong>Living with Heart Failure: A Patient''s Guide</strong>\n\nHeart failure occurs when the heart cannot pump blood effectively to meet the body''s needs. It doesn''t mean the heart has stopped beating, but rather that it''s not working as efficiently as it should.\n\n<strong>Types of Heart Failure:</strong>\n• <strong>Left-sided Heart Failure</strong>: Most common type\n• <strong>Right-sided Heart Failure</strong>: Often caused by left-sided failure\n• <strong>Congestive Heart Failure</strong>: Fluid buildup in the body\n\n<strong>Common Symptoms:</strong>\n• Shortness of breath\n• Fatigue and weakness\n• Swelling in legs, ankles, feet\n• Rapid or irregular heartbeat\n• Persistent cough or wheezing\n\n<strong>Treatment Options:</strong>\n\n<strong>Medications:</strong>\n• ACE inhibitors\n• Beta-blockers\n• Diuretics\n• Digoxin\n\n<strong>Lifestyle Modifications:</strong>\n• Low-sodium diet\n• Fluid restriction\n• Regular monitoring of weight\n• Moderate exercise\n\n<strong>Living with Heart Failure:</strong>\nManaging heart failure requires daily commitment. Regular check-ups, medication adherence, and lifestyle changes are essential for maintaining quality of life.\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. David Chen', 'https://randomuser.me/api/portraits/men/28.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/tP79YHgMmMg/maxresdefault.jpg', 'https://www.youtube.com/watch?v=tP79YHgMmMg', '2024-02-15 10:00:00', '8 min read', 0, 0, 0, false, true, 'living-with-heart-failure', NOW(), NOW()),

(8, 'The Future of Cardiology: AI and Heart Health', 'Explore how AI and technology are revolutionizing cardiology and heart health care.', '<strong>The Future of Cardiology: Innovations and Breakthroughs</strong>\n\nCardiology has undergone remarkable transformations over the past decades. From simple stethoscopes to AI-powered diagnostics, the field continues to evolve at an unprecedented pace.\n\n<strong>Artificial Intelligence in Cardiology:</strong>\nAI is revolutionizing heart care through:\n• <strong>Predictive Analytics</strong>: Identifying at-risk patients\n• <strong>Image Analysis</strong>: Automated interpretation of scans\n• <strong>Risk Assessment</strong>: Machine learning for personalized scores\n\n<strong>Advanced Imaging Technologies:</strong>\n• <strong>3D Echocardiography</strong>: Real-time 3D imaging\n• <strong>Cardiac MRI</strong>: Detailed imaging without radiation\n• <strong>CT Angiography</strong>: Non-invasive coronary artery imaging\n\n<strong>Revolutionary Treatments:</strong>\n• <strong>Gene Therapy</strong>: Treating genetic heart conditions\n• <strong>Stem Cell Therapy</strong>: Regenerating damaged heart tissue\n• <strong>Artificial Heart</strong>: Fully implantable artificial hearts\n\n<strong>Telemedicine and Remote Monitoring:</strong>\n• <strong>Remote ECG Monitoring</strong>: Continuous cardiac monitoring\n• <strong>Virtual Consultations</strong>: Access to cardiologists anywhere\n• <strong>Wearable Technology</strong>: Smartwatches detecting arrhythmias\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Cardiology', 'Dr. David Chen', 'https://randomuser.me/api/portraits/men/28.jpg', 'https://images.unsplash.com/photo-1516534775068-ba3e7458af70?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/7IkwuecP6r0/maxresdefault.jpg', 'https://www.youtube.com/watch?v=7IkwuecP6r0', '2024-02-20 10:00:00', '7 min read', 0, 0, 0, true, true, 'future-of-cardiology', NOW(), NOW());

-- NUTRITION & DIETETICS (8 posts) - Dr. Raj Patel (9-10), Dr. Sarah Johnson (11-12), Dr. Lisa Park (13-14), Dr. James Anderson (15-16)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(9, 'The Ultimate Guide to Heart-Healthy Nutrition', 'Discover the best and worst foods for your heart. Learn Mediterranean diet principles and meal planning.', '<strong>The Ultimate Guide to Heart-Healthy Nutrition</strong>\n\nWhat you eat directly impacts your heart health. This comprehensive guide covers the best and worst foods for your heart, including Mediterranean diet principles and practical meal planning strategies.\n\n<strong>Heart-Healthy Foods:</strong>\n\n<strong>Fruits and Vegetables:</strong>\n• Berries (blueberries, strawberries, raspberries)\n• Leafy greens (spinach, kale, Swiss chard)\n• Citrus fruits (oranges, grapefruits)\n• Avocados\n• Tomatoes\n\n<strong>Whole Grains:</strong>\n• Oats and oatmeal\n• Brown rice\n• Quinoa\n• Whole wheat bread\n• Barley\n\n<strong>Healthy Proteins:</strong>\n• Fatty fish (salmon, mackerel, tuna)\n• Lean poultry\n• Legumes (beans, lentils)\n• Nuts and seeds\n\n<strong>Healthy Fats:</strong>\n• Olive oil\n• Avocados\n• Nuts (almonds, walnuts)\n• Seeds (chia, flax)\n\n<strong>Foods to Limit or Avoid:</strong>\n• Saturated fats (red meat, butter, cheese)\n• Trans fats (fried foods, processed snacks)\n• Sodium (processed foods, canned soups)\n• Added sugars (sugary drinks, desserts)\n• Refined carbohydrates (white bread, white rice)\n\n<strong>Mediterranean Diet Principles:</strong>\n1. Eat plenty of fruits and vegetables\n2. Choose whole grains\n3. Include healthy fats (olive oil)\n4. Eat fish and poultry in moderation\n5. Limit red meat\n6. Enjoy meals with family and friends\n\n<strong>Meal Planning Tips:</strong>\n• Plan meals in advance\n• Cook at home more often\n• Read food labels carefully\n• Practice portion control\n• Stay hydrated with water\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/29.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/SBtRkjXSMmk/maxresdefault.jpg', 'https://www.youtube.com/watch?v=SBtRkjXSMmk', '2024-02-25 10:00:00', '10 min read', 0, 0, 0, true, true, 'heart-healthy-nutrition', NOW(), NOW()),

(10, 'Plant-Based Diet: Benefits and Meal Plans', 'Learn the benefits of a plant-based diet and get practical meal planning strategies.', '<strong>Plant-Based Diet: Benefits and Meal Plans</strong>\n\nMore people are adopting plant-based diets for health and environmental reasons. This guide covers the scientific evidence for plant-based nutrition and practical meal planning strategies.\n\n<strong>Benefits of a Plant-Based Diet:</strong>\n• Lower risk of heart disease\n• Reduced risk of type 2 diabetes\n• Lower blood pressure\n• Improved weight management\n• Reduced inflammation\n• Lower cancer risk\n• Environmental benefits\n\n<strong>Types of Plant-Based Diets:</strong>\n• <strong>Vegan</strong>: No animal products\n• <strong>Vegetarian</strong>: No meat, but may include dairy and eggs\n• <strong>Flexitarian</strong>: Mostly plant-based with occasional meat\n• <strong>Pescatarian</strong>: Plant-based plus fish\n\n<strong>Essential Nutrients on a Plant-Based Diet:</strong>\n• <strong>Protein</strong> (beans, lentils, tofu)\n• <strong>Iron</strong> (dark leafy greens, beans)\n• <strong>Calcium</strong> (fortified plant milks)\n• <strong>Vitamin B12</strong> (supplements or fortified foods)\n• <strong>Omega-3 fatty acids</strong> (flaxseeds, walnuts)\n• <strong>Vitamin D</strong> (sunlight, supplements)\n\n<strong>Tips for Transitioning:</strong>\n• Start with one meatless day per week\n• Try new plant-based recipes\n• Explore plant-based alternatives\n• Focus on adding, not subtracting\n• Find plant-based restaurants in your area\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/29.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/Hm87RL3p3PQ/maxresdefault.jpg', 'https://www.youtube.com/watch?v=Hm87RL3p3PQ', '2024-03-01 10:00:00', '8 min read', 0, 0, 0, false, true, 'plant-based-diet', NOW(), NOW()),

(11, 'Managing Diabetes Through Diet', 'Learn how to manage diabetes through diet. Includes carbohydrate counting and meal timing strategies.', '<strong>Managing Diabetes Through Diet: A Complete Guide</strong>\n\nDiet plays a crucial role in diabetes management. This guide provides practical tips for blood sugar control including carbohydrate counting and meal timing strategies.\n\n<strong>Understanding Diabetes:</strong>\nDiabetes is a chronic condition that affects how your body turns food into energy. There are two main types:\n• <strong>Type 1</strong>: The body doesn''t produce insulin\n• <strong>Type 2</strong>: The body doesn''t use insulin properly\n\n<strong>Dietary Principles for Diabetes:</strong>\n\n<strong>Carbohydrate Management:</strong>\n• Count carbohydrates consistently\n• Choose complex carbs over simple ones\n• Spread carbs throughout the day\n• Monitor portion sizes\n\n<strong>Glycemic Index:</strong>\nFoods with a low glycemic index raise blood sugar more slowly:\n• <strong>Low GI</strong>: Beans, legumes, whole grains\n• <strong>Medium GI</strong>: Brown rice, whole wheat bread\n• <strong>High GI</strong>: White bread, white rice, sugary foods\n\n<strong>Meal Timing:</strong>\n• Eat regular meals\n• Don''t skip meals\n• Consistent carbohydrate intake\n• Evening snack if needed\n\n<strong>Recommended Foods:</strong>\n• Non-starchy vegetables (broccoli, spinach, peppers)\n• Lean meats (chicken, turkey)\n• Fish (salmon, tuna)\n• Plant-based proteins (beans, lentils)\n• Whole grains (oats, brown rice, quinoa)\n\n<strong>Foods to Avoid:</strong>\n• Sugary beverages\n• Refined carbohydrates\n• Processed snacks\n• Trans fats\n• Excessive alcohol\n\n<strong>Meal Planning Tips:</strong>\n• Use the plate method (half vegetables, quarter protein, quarter carbs)\n• Read food labels carefully\n• Keep a food diary\n• Count carbohydrates\n• Test blood sugar regularly\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/3.jpg', 'https://images.unsplash.com/photo-1516534775068-ba3e7458af70?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/4o2-M1C6T5I/maxresdefault.jpg', 'https://www.youtube.com/watch?v=4o2-M1C6T5I', '2024-03-05 10:00:00', '9 min read', 0, 0, 0, false, true, 'managing-diabetes-diet', NOW(), NOW()),

(12, 'Superfoods for Brain Health', 'Discover superfoods that can improve memory, focus, and long-term brain health.', '<strong>Superfoods for Brain Health: Boost Your Cognitive Function</strong>\n\nThe brain requires specific nutrients to function optimally. This guide covers the superfoods that can improve memory, focus, and long-term brain health.\n\n<strong>Top Brain-Healthy Foods:</strong>\n\n<strong>Fatty Fish:</strong>\n• Salmon, mackerel, sardines\n• Rich in omega-3 fatty acids (EPA and DHA)\n• Supports brain cell structure\n• May improve memory and mood\n\n<strong>Blueberries:</strong>\n• High in antioxidants\n• May delay brain aging\n• Improves memory and cognitive function\n• Protects against oxidative stress\n\n<strong>Turmeric:</strong>\n• Contains curcumin (anti-inflammatory)\n• Crosses the blood-brain barrier\n• May improve memory and mood\n• Supports neurogenesis\n\n<strong>Dark Chocolate:</strong>\n• Contains flavonoids\n• Antioxidant and anti-inflammatory\n• May improve memory and mood\n• Increases blood flow to the brain\n\n<strong>Nuts:</strong>\n• Especially walnuts\n• Rich in healthy fats\n• May improve cognitive function\n• Protective against age-related decline\n\n<strong>Green Tea:</strong>\n• Contains caffeine and L-theanine\n• Improves alertness and focus\n• Antioxidant properties\n• May protect against neurodegenerative diseases\n\n<strong>Brain-Healthy Lifestyle Habits:</strong>\n• Regular exercise\n• Adequate sleep (7-8 hours)\n• Stress management\n• Social connections\n• Mental stimulation\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/3.jpg', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/GmK8aWMIjCM/maxresdefault.jpg', 'https://www.youtube.com/watch?v=GmK8aWMIjCM', '2024-03-10 10:00:00', '7 min read', 0, 0, 0, false, true, 'superfoods-brain-health', NOW(), NOW()),

(13, 'Intermittent Fasting: A Complete Guide', 'Learn about different fasting methods, what to eat, and how to get started safely.', '<strong>Intermittent Fasting: A Complete Guide to Health Benefits</strong>\n\nIntermittent fasting has gained popularity for its potential health benefits. This guide explains different fasting methods, what to eat, and how to get started safely.\n\n<strong>What is Intermittent Fasting?</strong>\nIntermittent fasting is an eating pattern that cycles between periods of eating and fasting. It focuses on when to eat rather than what to eat.\n\n<strong>Popular Fasting Methods:</strong>\n\n<strong>16/8 Method (Time-Restricted Eating):</strong>\n• Fast for 16 hours, eat within an 8-hour window\n• Example: Eat from 12 PM to 8 PM\n• Most popular and sustainable method\n\n<strong>5:2 Diet:</strong>\n• Eat normally for 5 days, restrict calories to 500-600 for 2 days\n• Fasting days can be non-consecutive\n• Flexible and easier to maintain\n\n<strong>Health Benefits:</strong>\n\n<strong>Metabolic Benefits:</strong>\n• Improved insulin sensitivity\n• Lower blood sugar levels\n• Increased metabolic rate\n• Fat loss while maintaining muscle\n\n<strong>Cellular Benefits:</strong>\n• Autophagy (cellular cleanup)\n• Reduced inflammation\n• Protection against chronic diseases\n• Slower aging process\n\n<strong>Getting Started Safely:</strong>\n\n<strong>Tips for Beginners:</strong>\n• Start with 12-hour fasts\n• Gradually extend fasting window\n• Stay hydrated during fasting\n• Eat nutrient-dense foods\n• Listen to your body\n\n<strong>Who Should Avoid Fasting:</strong>\n• Pregnant women\n• People with eating disorders\n• Those underweight\n• People with certain medical conditions\n• Consult a doctor first\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Lisa Park', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/RI5oYIUItN8/maxresdefault.jpg', 'https://www.youtube.com/watch?v=RI5oYIUItN8', '2024-03-15 10:00:00', '8 min read', 0, 0, 0, true, true, 'intermittent-fasting', NOW(), NOW()),

(14, 'Gut Health and Overall Wellness', 'Explore the connection between gut health and immunity, mental health, and chronic disease prevention.', '<strong>Gut Health and Overall Wellness: The Connection</strong>\n\nThe gut microbiome plays a crucial role in overall health. This guide explores the connection between gut health and immunity, mental health, and chronic disease prevention.\n\n<strong>Understanding the Gut Microbiome:</strong>\nThe gut microbiome consists of trillions of microorganisms living in your digestive tract. These bacteria, viruses, and fungi play a vital role in your health.\n\n<strong>Gut-Brain Connection:</strong>\n• Gut bacteria produce neurotransmitters\n• The vagus nerve connects the gut and brain\n• Gut health affects mood and mental health\n• Stress affects the gut microbiome\n\n<strong>Gut Health and Immunity:</strong>\n• 70% of immune cells are in the gut\n• Healthy microbiome supports immune function\n• Reduces inflammation\n• Protects against infections\n\n<strong>Signs of Poor Gut Health:</strong>\n• Digestive issues (bloating, gas, constipation)\n• Food intolerances\n• Autoimmune conditions\n• Fatigue and low energy\n• Skin problems\n\n<strong>Foods for Gut Health:</strong>\n\n<strong>Prebiotic Foods:</strong>\n• Garlic, Onions, Leeks\n• Asparagus, Bananas, Oats\n\n<strong>Probiotic Foods:</strong>\n• Yogurt, Kefir, Sauerkraut\n• Kimchi, Kombucha, Miso\n\n<strong>Fiber-Rich Foods:</strong>\n• Whole grains, Legumes\n• Fruits, Vegetables\n• Nuts and seeds\n\n<strong>Lifestyle Tips for Better Gut Health:</strong>\n• Eat a diverse range of foods\n• Include fermented foods\n• Manage stress levels\n• Get enough sleep\n• Stay hydrated\n• Exercise regularly\n• Limit processed foods\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. Lisa Park', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/X14lD_esCoM/maxresdefault.jpg', 'https://www.youtube.com/watch?v=X14lD_esCoM', '2024-03-20 10:00:00', '9 min read', 0, 0, 0, false, true, 'gut-health-wellness', NOW(), NOW()),

(15, 'Vitamin D: The Sunshine Vitamin', 'Learn about the importance of vitamin D, how to get enough, and the health benefits of maintaining optimal levels.', '<strong>Vitamin D: The Sunshine Vitamin - Essential Guide</strong>\n\nVitamin D deficiency is common worldwide. Learn about the importance of this essential vitamin, how to get enough, and the health benefits of maintaining optimal levels.\n\n<strong>What is Vitamin D?</strong>\nVitamin D is a fat-soluble vitamin that acts like a hormone in the body. It''s essential for many bodily functions including:\n• Calcium absorption\n• Bone health\n• Immune function\n• Cell growth\n• Inflammation regulation\n\n<strong>Sources of Vitamin D:</strong>\n\n<strong>Sunlight:</strong>\n• The body produces vitamin D when skin is exposed to UVB rays\n• 10-30 minutes of sun exposure (depending on skin type)\n• Time of day and location affect production\n• Sunscreen can reduce production\n\n<strong>Food Sources:</strong>\n• Fatty fish (salmon, mackerel, sardines)\n• Egg yolks\n• Cod liver oil\n• Fortified foods (milk, orange juice, cereals)\n• Mushrooms exposed to UV light\n\n<strong>Supplements:</strong>\n• Available as D2 (ergocalciferol) and D3 (cholecalciferol)\n• D3 is more effective\n• Available in various dosages\n\n<strong>Health Benefits:</strong>\n• Stronger bones and teeth\n• Better immune function\n• Reduced depression risk\n• Lower cancer risk\n• Heart health support\n• Weight management\n\n<strong>Risk Factors for Deficiency:</strong>\n• Limited sun exposure\n• Darker skin\n• Older age\n• Obesity\n• Digestive issues\n• Vegetarian/vegan diet\n\n<strong>Recommended Intake:</strong>\n• Infants: 400 IU\n• Children and adults: 600-800 IU\n• Elderly: 800-1000 IU\n• Pregnant women: 600 IU\n\n<strong>Signs of Deficiency:</strong>\n• Bone pain\n• Muscle weakness\n• Fatigue\n• Mood changes\n• Hair loss\n• Slow wound healing\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. James Anderson', 'https://randomuser.me/api/portraits/men/30.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/iLDYbSX5MLA/maxresdefault.jpg', 'https://www.youtube.com/watch?v=iLDYbSX5MLA', '2024-03-25 10:00:00', '6 min read', 0, 0, 0, false, true, 'vitamin-d-guide', NOW(), NOW()),

(16, 'Healthy Eating on a Budget', 'Practical tips for meal planning, smart shopping, and preparing nutritious meals on a budget.', '<strong>Healthy Eating on a Budget: Smart Strategies</strong>\n\nEating healthy doesn''t have to be expensive. This guide provides practical tips for meal planning, smart shopping, and preparing nutritious meals on a budget.\n\n<strong>Smart Shopping Tips:</strong>\n\n<strong>Plan Ahead:</strong>\n• Make a weekly meal plan\n• Create a grocery list\n• Check sales and coupons\n• Shop with a list and stick to it\n\n<strong>Shop Smart:</strong>\n• Buy in bulk (items you use frequently)\n• Shop seasonal produce\n• Visit farmers markets\n• Compare prices per unit\n• Choose store brands\n\n<strong>Save on Protein:</strong>\n• Beans and lentils (inexpensive protein)\n• Eggs (versatile and affordable)\n• Canned fish (tuna, sardines)\n• Chicken thighs (cheaper than breast)\n• Tofu (plant-based protein)\n\n<strong>Save on Produce:</strong>\n• Buy seasonal fruits and vegetables\n• Frozen vegetables (just as nutritious)\n• Canned vegetables (low-sodium options)\n• Grow your own herbs\n\n<strong>Budget-Friendly Meal Ideas:</strong>\n\n<strong>Breakfast:</strong>\n• Oatmeal with fruit and nuts\n• Eggs with vegetables\n• Whole grain toast with avocado\n• Yogurt with granola\n\n<strong>Lunch:</strong>\n• Bean and vegetable soup\n• Hummus and vegetable wraps\n• Tuna or egg salad sandwiches\n• Quinoa and vegetable bowls\n\n<strong>Dinner:</strong>\n• Lentil or bean chili\n• Vegetable stir-fry with rice\n• Pasta with vegetable sauce\n• Black bean burritos\n• Baked potato with toppings\n\n<strong>Reduce Food Waste:</strong>\n• Use leftovers creatively\n• Freeze extras for later\n• Keep an inventory\n• Store food properly\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Nutrition & Dietetics', 'Dr. James Anderson', 'https://randomuser.me/api/portraits/men/30.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/oS0UW2664KY/maxresdefault.jpg', 'https://www.youtube.com/watch?v=oS0UW2664KY', '2024-03-30 10:00:00', '7 min read', 0, 0, 0, false, true, 'healthy-eating-budget', NOW(), NOW());

-- PHYSICAL THERAPY (8 posts) - Dr. Maya Lee (17-18), Dr. Kevin Brown (19-20), Dr. Amanda Green (21-22), Dr. Arthur Pendelton (23-24)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(17, 'Rehab After Knee Surgery: A Complete Guide', 'Covers everything from day 1 post-surgery to full recovery including exercises and pain management.', '<strong>Rehab After Knee Surgery: A Complete Guide</strong>\n\nKnee surgery recovery requires dedication and the right approach. This guide covers everything from day 1 post-surgery to full recovery including exercises and pain management strategies.\n\n<strong>Understanding Knee Surgery Recovery:</strong>\nKnee surgery is a major procedure that requires comprehensive rehabilitation. The success of surgery depends significantly on the quality of rehabilitation.\n\n<strong>Immediate Post-Surgery Phase (Days 1-7):</strong>\n\n<strong>Hospital Recovery:</strong>\n• Pain management\n• Range of motion exercises (gentle)\n• Basic muscle activation\n• Crutch training\n• Wound care\n\n<strong>Initial Exercises:</strong>\n• Ankle pumps (prevent blood clots)\n• Quad sets (activate thigh muscles)\n• Heel slides (gentle knee bending)\n• Straight leg raises (leg lifts)\n\n<strong>Rehabilitation Phases:</strong>\n\n<strong>Phase 1: Recovery (Weeks 1-4):</strong>\n• Light range of motion exercises\n• Gentle stretching\n• Pain management\n• Gradual weight bearing\n• Basic daily activities\n\n<strong>Phase 2: Strengthening (Weeks 4-8):</strong>\n• Progressive range of motion\n• Strengthening exercises\n• Balance training\n• Increased weight bearing\n• Stationary cycling\n\n<strong>Phase 3: Advanced Strengthening (Weeks 8-12):</strong>\n• Full range of motion\n• Strengthening and flexibility\n• Balance and proprioception\n• Walking with less support\n• Low-impact activities\n\n<strong>Phase 4: Return to Activity (Months 3-6):</strong>\n• Return to work\n• Low-impact sports\n• Full strengthening\n• Gait training\n• Advanced functional exercises\n\n<strong>Important Exercises:</strong>\n\n<strong>Quad Exercises:</strong>\n• Quad sets (tighten thigh muscles)\n• Straight leg raises\n• Step-ups\n\n<strong>Hamstring Exercises:</strong>\n• Hamstring sets\n• Prone leg curls\n• Standing leg curls\n\n<strong>Stretching Exercises:</strong>\n• Heel slides\n• Knee extension stretches\n• Calf stretches\n\n<strong>Pain Management:</strong>\n• Ice therapy (20 minutes, 3-4 times daily)\n• Elevation (above heart level)\n• Medications as prescribed\n• Gentle movement\n\n<strong>Tips for Successful Recovery:</strong>\n• Follow your physical therapist''s instructions\n• Exercise daily (but don''t overdo it)\n• Manage pain effectively\n• Eat nutritious food\n• Get adequate rest\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Maya Lee', 'https://randomuser.me/api/portraits/women/5.jpg', 'https://images.unsplash.com/photo-1516534775068-ba3e7458af70?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/ooqJCdq0ucs/maxresdefault.jpg', 'https://www.youtube.com/watch?v=ooqJCdq0ucs', '2024-04-01 10:00:00', '10 min read', 0, 0, 0, true, true, 'knee-surgery-rehab', NOW(), NOW()),

(18, 'Sports Injury Prevention: Expert Tips', 'Learn proper warm-up techniques, strength training fundamentals, and recovery strategies.', '<strong>Sports Injury Prevention: Expert Tips and Strategies</strong>\n\nWhether you''re a weekend warrior or a professional athlete, injury prevention is key to long-term athletic success. This guide covers proper warm-up techniques, strength training fundamentals, and recovery strategies.\n\n<strong>Understanding Sports Injuries:</strong>\nSports injuries are common but many are preventable. Understanding the causes helps in prevention.\n\n<strong>Common Sports Injuries:</strong>\n• Sprains and strains (ligament and muscle injuries)\n• Tendonitis (overuse injuries)\n• Fractures (bone breaks)\n• Concussions (head injuries)\n• Dislocations (joint injuries)\n• Shin splints (leg pain)\n\n<strong>Prevention Strategies:</strong>\n\n<strong>Proper Warm-Up:</strong>\n• Light cardio (5-10 minutes)\n• Dynamic stretching (leg swings, arm circles)\n• Sport-specific drills\n• Gradually increase intensity\n\n<strong>Proper Cool-Down:</strong>\n• Light cardio (5-10 minutes)\n• Static stretching (hold for 15-30 seconds)\n• Self-massage (foam rolling)\n• Hydration and nutrition\n\n<strong>Strength Training:</strong>\n• Core strengthening\n• Stabilizer muscles\n• Sport-specific training\n• Proper form and technique\n\n<strong>Flexibility:</strong>\n• Regular stretching (3-5 times per week)\n• Yoga or Pilates\n• Maintain range of motion\n\n<strong>Proper Technique:</strong>\n• Learn proper form\n• Use proper equipment\n• Avoid overtraining\n• Listen to your body\n\n<strong>Injury Management:</strong>\n• RICE: Rest, Ice, Compression, Elevation\n• Seek medical attention for serious injuries\n• Follow rehabilitation protocols\n• Gradual return to activity\n\n<strong>Nutrition for Injury Prevention:</strong>\n• Adequate protein\n• Anti-inflammatory foods\n• Hydration\n• Proper fueling\n\n<strong>When to Seek Professional Help:</strong>\n• Persistent pain\n• Swelling that doesn''t improve\n• Difficulty bearing weight\n• Decreased range of motion\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Maya Lee', 'https://randomuser.me/api/portraits/women/5.jpg', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/ZG55IYPFGQ0/maxresdefault.jpg', 'https://www.youtube.com/watch?v=ZG55IYPFGQ0', '2024-04-05 10:00:00', '9 min read', 0, 0, 0, false, true, 'sports-injury-prevention', NOW(), NOW()),

(19, 'Lower Back Pain: Causes and Treatment', 'Explores the common causes and provides evidence-based treatment options for relief and prevention.', '<strong>Lower Back Pain: Causes and Effective Treatment</strong>\n\nLower back pain affects millions of people worldwide. This guide explores the common causes and provides evidence-based treatment options for relief and prevention.\n\n<strong>Understanding Lower Back Pain:</strong>\nLower back pain is one of the most common health complaints worldwide, affecting up to 80% of people at some point in their lives.\n\n<strong>Common Causes:</strong>\n\n<strong>Muscle Strains:</strong>\n• Poor posture\n• Lifting heavy objects\n• Sudden movements\n• Prolonged sitting\n\n<strong>Spinal Issues:</strong>\n• Herniated discs\n• Degenerative disc disease\n• Spinal stenosis\n• Spondylolisthesis\n\n<strong>Osteoarthritis:</strong>\n• Joint degeneration\n• Bone spurs\n• Inflammation\n\n<strong>Treatment Options:</strong>\n\n<strong>Conservative Treatment:</strong>\n• Rest (short-term)\n• Ice and heat therapy\n• Over-the-counter pain medications\n• Gentle movement\n\n<strong>Physical Therapy:</strong>\n• Core strengthening\n• Stretching exercises\n• Posture correction\n• Manual therapy\n\n<strong>Medications:</strong>\n• NSAIDs (ibuprofen, naproxen)\n• Muscle relaxants\n• Prescription pain medications\n\n<strong>Alternative Therapies:</strong>\n• Acupuncture\n• Chiropractic care\n• Massage therapy\n• Yoga and Pilates\n\n<strong>Prevention Strategies:</strong>\n• Maintain good posture\n• Exercise regularly\n• Strengthen core muscles\n• Practice proper lifting techniques\n• Maintain healthy weight\n• Use ergonomic furniture\n\n<strong>When to See a Doctor:</strong>\n• Severe pain that doesn''t improve\n• Pain radiating to legs\n• Numbness or tingling\n• Loss of bowel/bladder control\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Kevin Brown', 'https://randomuser.me/api/portraits/men/31.jpg', 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/vRS0je8eopc/maxresdefault.jpg', 'https://www.youtube.com/watch?v=vRS0je8eopc', '2024-04-10 10:00:00', '8 min read', 0, 0, 0, false, true, 'lower-back-pain', NOW(), NOW()),

(20, 'Posture Correction: Exercises and Tips', 'Practical exercises and daily habits for improving your posture and reducing pain.', '<strong>Posture Correction: Exercises and Daily Habits</strong>\n\nPoor posture can lead to various health issues including back pain, neck pain, and headaches. This guide provides practical exercises and tips for improving your posture.\n\n<strong>Understanding Posture:</strong>\nGood posture involves training your body to stand, walk, sit, and lie in positions that place the least strain on supporting muscles and ligaments.\n\n<strong>Signs of Poor Posture:</strong>\n• Rounded shoulders\n• Forward head position\n• Slouching\n• Hunching\n• Uneven shoulders or hips\n\n<strong>Exercises for Better Posture:</strong>\n\n<strong>Neck Stretches:</strong>\n• Chin tucks (pull chin back)\n• Neck rotations\n• Side-to-side stretches\n\n<strong>Shoulder Exercises:</strong>\n• Shoulder rolls (forward and backward)\n• Shoulder blade squeezes (retract shoulders)\n• Arm circles (small and large)\n\n<strong>Back Exercises:</strong>\n• Cat-Cow stretch (stretches entire spine)\n• Cobra pose (opening chest)\n• Child''s pose (stretching back)\n\n<strong>Core Exercises:</strong>\n• Planks\n• Bird-dog\n• Dead bug\n• Partial crunches\n\n<strong>Daily Habits for Better Posture:</strong>\n\n<strong>Sitting at a Desk:</strong>\n• Adjust chair height\n• Keep feet flat on floor\n• Monitor at eye level\n• Take regular breaks\n• Use lumbar support\n\n<strong>Standing:</strong>\n• Weight evenly distributed\n• Knees slightly bent\n• Shoulders back and relaxed\n• Head level\n\n<strong>Sleeping:</strong>\n• Supportive pillow\n• Sleeping on back or side\n• Proper mattress support\n\n<strong>Ergonomic Tips:</strong>\n• Use ergonomic furniture\n• Position monitor at eye level\n• Use a headset for calls\n• Take walking breaks\n• Alternate sitting and standing\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Kevin Brown', 'https://randomuser.me/api/portraits/men/31.jpg', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/jB1Yb9PMm-U/maxresdefault.jpg', 'https://www.youtube.com/watch?v=jB1Yb9PMm-U', '2024-04-15 10:00:00', '7 min read', 0, 0, 0, false, true, 'posture-correction', NOW(), NOW()),

(21, 'Shoulder Injury Rehabilitation', 'Covers rehabilitation exercises, recovery timelines, and prevention strategies for shoulder injuries.', '<strong>Shoulder Injury Rehabilitation: A Complete Guide</strong>\n\nShoulder injuries are common in sports and daily life. This guide covers rehabilitation exercises, recovery timelines, and prevention strategies for shoulder injuries.\n\n<strong>Understanding Shoulder Injuries:</strong>\nThe shoulder is the most mobile joint in the body, making it susceptible to injury and instability.\n\n<strong>Common Shoulder Injuries:</strong>\n• Rotator cuff tears\n• Shoulder impingement\n• Frozen shoulder (adhesive capsulitis)\n• Shoulder dislocation\n• Labrum tears\n• Tendonitis (bicipital)\n\n<strong>Rehabilitation Phases:</strong>\n\n<strong>Phase 1: Acute Phase (Days 1-14):</strong>\n• Rest and protection\n• Pain and swelling management\n• Gentle range of motion\n• Ice therapy\n• Immobilization (if needed)\n\n<strong>Phase 2: Recovery Phase (Weeks 3-8):</strong>\n• Gentle stretching\n• Scapular stabilization\n• Rotator cuff strengthening\n• Posture correction\n• Gradual activity\n\n<strong>Phase 3: Strengthening Phase (Weeks 9-16):</strong>\n• Progressive strengthening\n• Full range of motion\n• Functional exercises\n• Sport-specific training\n\n<strong>Phase 4: Return to Activity (Months 4-6):</strong>\n• Return to work\n• Return to sports\n• Maintenance program\n• Prevention focus\n\n<strong>Key Exercises:</strong>\n\n<strong>Rotator Cuff Exercises:</strong>\n• External rotation with bands\n• Internal rotation with bands\n• Scapular push-ups\n• Arm raises (front and side)\n\n<strong>Stabilization Exercises:</strong>\n• Wall push-ups\n• Plank variations\n• Scapular retraction\n• YTWL exercises\n\n<strong>Stretching:</strong>\n• Pendulum swings\n• Cross-body stretch\n• Sleeper stretch\n• Doorway stretch\n\n<strong>Prevention Strategies:</strong>\n• Strengthen rotator cuff\n• Improve flexibility\n• Proper technique\n• Avoid overuse\n• Listen to your body\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Amanda Green', 'https://randomuser.me/api/portraits/women/6.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/ldUwIBccnuw/maxresdefault.jpg', 'https://www.youtube.com/watch?v=ldUwIBccnuw', '2024-04-20 10:00:00', '9 min read', 0, 0, 0, false, true, 'shoulder-injury-rehab', NOW(), NOW()),

(22, 'Walking for Health: Benefits and Tips', 'Covers health benefits and practical tips for starting a walking routine.', '<strong>Walking for Health: Benefits and Tips</strong>\n\nWalking is one of the simplest and most effective forms of exercise. This guide covers its health benefits and practical tips for starting a walking routine.\n\n<strong>Health Benefits of Walking:</strong>\n\n<strong>Heart Health:</strong>\n• Lowers blood pressure\n• Reduces cholesterol\n• Decreases heart disease risk\n• Improves circulation\n\n<strong>Weight Management:</strong>\n• Burns calories\n• Speeds metabolism\n• Maintains muscle mass\n• Supports weight loss\n\n<strong>Mental Health:</strong>\n• Reduces stress and anxiety\n• Improves mood\n• Boosts creativity\n• Enhances memory\n\n<strong>Bone and Joint Health:</strong>\n• Strengthens bones\n• Reduces arthritis pain\n• Improves balance\n• Prevents osteoporosis\n\n<strong>Getting Started:</strong>\n\n<strong>Tips for Beginners:</strong>\n• Start with short walks (10-15 minutes)\n• Walk 3-4 times per week\n• Wear comfortable shoes\n• Choose a pleasant route\n• Warm up and cool down\n\n<strong>Progressive Plan:</strong>\n• Week 1-2: 15 minutes, 3 times/week\n• Week 3-4: 20-25 minutes, 4 times/week\n• Week 5-6: 30 minutes, 5 times/week\n• Week 7+: 30-45 minutes, daily\n\n<strong>Walking Techniques:</strong>\n• Good posture (head up, shoulders back)\n• Natural stride\n• Arm swing\n• Heel-to-toe movement\n\n<strong>Making Walking Enjoyable:</strong>\n• Listen to music or podcasts\n• Walk with friends\n• Explore new routes\n• Track your progress\n• Set goals\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Amanda Green', 'https://randomuser.me/api/portraits/women/6.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/xBesU4JK3tY/maxresdefault.jpg', 'https://www.youtube.com/watch?v=xBesU4JK3tY', '2024-04-25 10:00:00', '6 min read', 0, 0, 0, false, true, 'walking-for-health', NOW(), NOW()),

(23, 'Annual Health Checkup: What to Expect', 'Explains what tests you need, how to prepare, and how to make the most of your visit.', '<strong>Annual Health Checkup: What to Expect</strong>\n\nAnnual checkups are essential for preventive care. This guide explains what tests you need, how to prepare, and how to make the most of your visit.\n\n<strong>Why Annual Checkups Matter:</strong>\n• Early detection of conditions\n• Prevention of disease\n• Monitoring chronic conditions\n• Maintaining overall health\n\n<strong>What to Expect:</strong>\n\n<strong>Medical History Review:</strong>\n• Current medications\n• Previous conditions\n• Family history\n• Lifestyle habits\n\n<strong>Vital Signs:</strong>\n• Blood pressure\n• Heart rate\n• Respiration rate\n• Temperature\n\n<strong>Physical Examination:</strong>\n• General appearance\n• Heart and lung sounds\n• Abdomen palpation\n• Neurological assessment\n\n<strong>Common Tests:</strong>\n• Blood tests (CBC, cholesterol, glucose)\n• Urinalysis\n• Vision screening\n• Hearing test\n\n<strong>Age-Specific Screenings:</strong>\n• Mammograms (women over 40)\n• Prostate exam (men over 50)\n• Colonoscopy (over 45)\n• Bone density (over 65)\n\n<strong>Preparation Tips:</strong>\n• Bring medication list\n• Fast if needed\n• Wear comfortable clothing\n• Write down questions\n• Bring medical records\n\n<strong>Questions to Ask:</strong>\n• What tests do I need?\n• What are my risk factors?\n• How can I improve my health?\n• Do I need any vaccines?\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Arthur Pendelton', 'https://randomuser.me/api/portraits/men/32.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/CJOT7vCxfjQ/maxresdefault.jpg', 'https://www.youtube.com/watch?v=CJOT7vCxfjQ', '2024-05-01 10:00:00', '7 min read', 0, 0, 0, true, true, 'annual-health-checkup', NOW(), NOW()),

(24, 'Understanding the Flu: Symptoms and Treatment', 'Helps you understand symptoms, treatment options, and when to seek medical attention.', '<strong>Understanding the Flu: Symptoms and Treatment</strong>\n\nInfluenza affects millions each year. This guide helps you understand symptoms, treatment options, and when to seek medical attention.\n\n<strong>Understanding the Flu:</strong>\nInfluenza is a viral infection that affects the respiratory system. It''s highly contagious and can cause severe complications.\n\n<strong>Symptoms:</strong>\n• Fever (often high)\n• Chills\n• Muscle aches\n• Cough\n• Sore throat\n• Runny or stuffy nose\n• Fatigue\n• Headache\n\n<strong>When to Seek Emergency Care:</strong>\n• Difficulty breathing\n• Chest pain\n• Severe headache\n• Confusion\n• Persistent vomiting\n• High fever\n\n<strong>Treatment Options:</strong>\n\n<strong>Self-Care:</strong>\n• Rest (stay home)\n• Hydration (water, clear fluids)\n• Over-the-counter pain relievers\n• Steam inhalation\n\n<strong>Antiviral Medications:</strong>\n• Oseltamivir (Tamiflu)\n• Zanamivir (Relenza)\n• Peramivir (Rapivab)\n• Start within 48 hours\n\n<strong>Prevention:</strong>\n• Annual flu vaccine\n• Good hygiene (hand washing)\n• Avoid close contact\n• Cover coughs and sneezes\n\n<strong>Recovery Tips:</strong>\n• Get plenty of rest\n• Stay hydrated\n• Eat nutritious food\n• Avoid exertion\n• Stay home until fever-free\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Physical Therapy', 'Dr. Arthur Pendelton', 'https://randomuser.me/api/portraits/men/32.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/HsgsmO1G8Es/maxresdefault.jpg', 'https://www.youtube.com/watch?v=HsgsmO1G8Es', '2024-05-05 10:00:00', '8 min read', 0, 0, 0, false, true, 'understanding-flu', NOW(), NOW());

-- GENERAL MEDICINE (8 posts) - Dr. Rachel Adams (25-26), Dr. Thomas Wright (27-28), Dr. Laura Martinez (29-30), Dr. Michael Chen (31-32)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(25, 'The Importance of Sleep for Health', 'Explores the science of sleep and provides practical tips for better sleep hygiene.', '<strong>The Importance of Sleep for Health and Wellbeing</strong>\n\nSleep plays a vital role in overall health. This guide explores the science of sleep and provides practical tips for better sleep hygiene.\n\n<strong>Understanding Sleep:</strong>\nSleep is a complex physiological process essential for physical and mental health. It affects virtually every system in the body.\n\n<strong>Benefits of Sleep:</strong>\n\n<strong>Physical Health:</strong>\n• Tissue repair and growth\n• Immune function\n• Heart health\n• Weight management\n• Athletic performance\n\n<strong>Mental Health:</strong>\n• Cognitive function\n• Memory consolidation\n• Emotional regulation\n• Mental clarity\n• Stress reduction\n\n<strong>Long-term Health:</strong>\n• Reduced disease risk\n• Longer life expectancy\n• Better quality of life\n\n<strong>How Much Sleep Do You Need?</strong>\n• Adults: 7-9 hours\n• Teenagers: 8-10 hours\n• Children: 9-12 hours\n• Elderly: 7-8 hours\n\n<strong>Sleep Hygiene Tips:</strong>\n\n<strong>Daily Habits:</strong>\n• Consistent sleep schedule\n• Regular exercise\n• Avoid caffeine late in day\n• Limit alcohol before bed\n• Don''t eat large meals before bed\n\n<strong>Sleep Environment:</strong>\n• Dark, quiet, cool room\n• Comfortable mattress and pillows\n• Avoid screens 1 hour before bed\n• Use blackout curtains\n\n<strong>Relaxation Techniques:</strong>\n• Deep breathing\n• Progressive muscle relaxation\n• Mindfulness meditation\n• Reading (not on screens)\n\n<strong>Common Sleep Disorders:</strong>\n• Insomnia\n• Sleep apnea\n• Restless leg syndrome\n• Narcolepsy\n\n<strong>When to Seek Help:</strong>\n• Difficulty falling asleep\n• Waking frequently\n• Daytime sleepiness\n• Loud snoring\n• Leg discomfort\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Rachel Adams', 'https://randomuser.me/api/portraits/women/7.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/idxpEd-ZME4/maxresdefault.jpg', 'https://www.youtube.com/watch?v=idxpEd-ZME4', '2024-05-10 10:00:00', '9 min read', 0, 0, 0, false, true, 'importance-of-sleep', NOW(), NOW()),

(26, 'Stress Management Techniques for Daily Life', 'Provides effective techniques for managing stress and improving overall well-being.', '<strong>Stress Management Techniques for Daily Life</strong>\n\nStress is a common part of modern life. This guide provides effective techniques for managing stress and improving overall well-being.\n\n<strong>Understanding Stress:</strong>\nStress is the body''s response to demands or threats. While short-term stress can be beneficial, chronic stress can lead to serious health problems.\n\n<strong>Signs of Stress:</strong>\n• Sleep problems\n• Anxiety\n• Irritability\n• Difficulty concentrating\n• Physical tension\n\n<strong>Stress Management Techniques:</strong>\n\n<strong>Mindfulness:</strong>\n• Present-moment awareness\n• Body scanning\n• Mindful breathing\n• Mindful walking\n\n<strong>Relaxation Techniques:</strong>\n• Progressive muscle relaxation\n• Guided imagery\n• Autogenic training\n• Visualization\n\n<strong>Physical Activity:</strong>\n• Regular exercise\n• Walking in nature\n• Yoga\n• Swimming\n\n<strong>Healthy Lifestyle:</strong>\n• Adequate sleep\n• Balanced nutrition\n• Limit alcohol/caffeine\n• Regular meals\n\n<strong>Social Connections:</strong>\n• Talk to friends/family\n• Join support groups\n• Volunteer\n• Connect with others\n\n<strong>Time Management:</strong>\n• Prioritize tasks\n• Set realistic goals\n• Delegate when possible\n• Take breaks\n\n<strong>Quick Stress Relief:</strong>\n• Deep breathing (4-7-8 method)\n• Short walk\n• Listen to music\n• Call a friend\n• Take a break\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Rachel Adams', 'https://randomuser.me/api/portraits/women/7.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/TYWI929nZKg/maxresdefault.jpg', 'https://www.youtube.com/watch?v=TYWI929nZKg', '2024-05-15 10:00:00', '8 min read', 0, 0, 0, false, true, 'stress-management', NOW(), NOW()),

(27, 'Common Skin Conditions and Their Treatment', 'Covers common skin issues like acne, eczema, psoriasis, and their treatment options.', '<strong>Common Skin Conditions and Their Treatment</strong>\n\nSkin conditions can affect anyone. This guide covers common skin issues like acne, eczema, psoriasis, and their treatment options.\n\n<strong>Common Skin Conditions:</strong>\n\n<strong>Acne:</strong>\n• Most common skin condition\n• Clogged pores with bacteria\n• Hormonal influences\n• Affects face, back, chest\n\n<strong>Treatment Options:</strong>\n• Topical retinoids\n• Benzoyl peroxide\n• Antibiotics\n• Hormonal therapy (birth control)\n• Isotretinoin (severe cases)\n\n<strong>Eczema (Atopic Dermatitis):</strong>\n• Chronic, inflammatory skin condition\n• Itchy, dry, red skin\n• Often affects children\n• Associated with allergies\n\n<strong>Treatment Options:</strong>\n• Moisturizers\n• Topical corticosteroids\n• Calcineurin inhibitors\n• Antihistamines\n• Phototherapy\n\n<strong>Psoriasis:</strong>\n• Chronic autoimmune condition\n• Rapid skin cell turnover\n• Thick, scaly patches\n• Affects skin, nails, joints\n\n<strong>Treatment Options:</strong>\n• Topical treatments\n• Phototherapy\n• Systemic medications\n• Biologics\n\n<strong>Rosacea:</strong>\n• Redness and flushing on face\n• Visible blood vessels\n• Small, red bumps\n• Usually affects fair skin\n\n<strong>Treatment Options:</strong>\n• Topical medications\n• Oral antibiotics\n• Laser therapy\n• Avoid triggers\n\n<strong>Skin Cancer:</strong>\n• Most common cancer worldwide\n• Sun exposure major risk factor\n• Check moles regularly\n\n<strong>Types:</strong>\n• Basal cell carcinoma\n• Squamous cell carcinoma\n• Melanoma\n\n<strong>Prevention Tips:</strong>\n• Use sunscreen (SPF 30+)\n• Avoid excessive sun exposure\n• Regular skin self-examination\n• Wear protective clothing\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Thomas Wright', 'https://randomuser.me/api/portraits/men/33.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/uRqJChXxNnA/maxresdefault.jpg', 'https://www.youtube.com/watch?v=uRqJChXxNnA', '2024-05-20 10:00:00', '10 min read', 0, 0, 0, false, true, 'common-skin-conditions', NOW(), NOW()),

(28, 'Immunization: What You Need to Know', 'Covers different types of vaccines, immunization schedules, and the importance of herd immunity.', '<strong>Immunization: What You Need to Know</strong>\n\nVaccines are one of the most effective public health interventions. This guide covers different types of vaccines, immunization schedules, and the importance of herd immunity.\n\n<strong>How Vaccines Work:</strong>\n• Stimulate immune response\n• Develop antibodies\n• Protect against future infection\n• Prevent disease transmission\n\n<strong>Types of Vaccines:</strong>\n• Live-attenuated (MMR, chickenpox)\n• Inactivated (Polio, Hepatitis A)\n• Subunit (Whooping cough, HPV)\n• mRNA (COVID-19)\n• Vector-based (Ebola)\n\n<strong>Recommended Immunization Schedule:</strong>\n\n<strong>Childhood (0-18 years):</strong>\n• Hepatitis B (at birth)\n• DTaP (2,4,6 months)\n• Rotavirus (2,4 months)\n• IPV (2,4,6 months)\n• MMR (12 months)\n• Varicella (12 months)\n• Hepatitis A (12 months)\n\n<strong>Adolescent:</strong>\n• Tdap (booster)\n• HPV vaccine\n• Meningococcal\n• Flu vaccine (yearly)\n\n<strong>Adult:</strong>\n• Flu vaccine (yearly)\n• Td/Tdap (every 10 years)\n• Shingles (over 50)\n• Pneumococcal (over 65)\n\n<strong>Herd Immunity:</strong>\n• Protects vulnerable individuals\n• Reduces transmission\n• Community protection\n• Importance of high vaccination rates\n\n<strong>Common Side Effects:</strong>\n• Sore injection site\n• Low fever\n• Fatigue\n• Temporary pain\n\n<strong>When to Consult a Doctor:</strong>\n• Severe allergic reactions\n• Guillain-Barré syndrome\n• Immunocompromised conditions\n• Pregnancy concerns\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Thomas Wright', 'https://randomuser.me/api/portraits/men/33.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/Cb4GgtBt3PU/maxresdefault.jpg', 'https://www.youtube.com/watch?v=Cb4GgtBt3PU', '2024-05-25 10:00:00', '9 min read', 0, 0, 0, true, true, 'immunization-guide', NOW(), NOW()),

(29, 'Childhood Vaccinations: Everything You Need to Know', 'Answers all your questions about vaccine schedules, safety, and efficacy.', '<strong>Childhood Vaccinations: Everything You Need to Know</strong>\n\nVaccinations are crucial for protecting children from serious diseases. This guide answers all your questions about vaccine schedules, safety, and efficacy.\n\n<strong>Why Vaccinations Matter:</strong>\nVaccines protect children from potentially life-threatening diseases. They are safe, effective, and have saved millions of lives.\n\n<strong>Recommended Vaccination Schedule:</strong>\n• Birth: Hepatitis B\n• 2 months: DTaP, IPV, Hib, PCV, Rotavirus\n• 4 months: DTaP, IPV, Hib, PCV, Rotavirus\n• 6 months: DTaP, IPV, Hib, PCV, Rotavirus\n• 12-15 months: MMR, Varicella, Hib, PCV\n• 4-6 years: DTaP, IPV, MMR, Varicella\n• 11-12 years: Tdap, HPV, Meningococcal\n\n<strong>Vaccine Safety:</strong>\n• Vaccines are rigorously tested\n• Side effects are usually mild\n• Benefits far outweigh risks\n• Herd immunity protects vulnerable children\n\n<strong>Common Concerns:</strong>\n• Autism and vaccines (no link found)\n• Multiple vaccines at once (safe and effective)\n• Natural immunity vs. vaccine immunity (vaccines are safer)\n\n<strong>When to Delay Vaccination:</strong>\n• Moderate to severe illness\n• Allergic reaction to previous dose\n• Immunocompromised conditions\n• Consult your pediatrician\n\n<strong>Keeping Vaccination Records:</strong>\n• Keep a vaccination card\n• Track with mobile apps\n• Share with schools and healthcare providers\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Laura Martinez', 'https://randomuser.me/api/portraits/women/8.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/IH_U1OKV06Q/maxresdefault.jpg', 'https://www.youtube.com/watch?v=IH_U1OKV06Q', '2024-06-01 10:00:00', '8 min read', 0, 0, 0, false, true, 'childhood-vaccinations', NOW(), NOW()),

(30, 'Nutrition for Growing Children', 'Covers nutritional needs for different age groups and tips for healthy eating habits.', '<strong>Nutrition for Growing Children</strong>\n\nProper nutrition is crucial for children''s growth and development. This guide covers nutritional needs for different age groups and tips for healthy eating habits.\n\n<strong>Why Nutrition Matters:</strong>\nChildren need proper nutrition for:\n• Physical growth\n• Brain development\n• Immune function\n• Energy for play and learning\n\n<strong>Nutritional Needs by Age:</strong>\n\n<strong>Infants (0-12 months):</strong>\n• Breast milk or formula\n• Introduction of solids at 6 months\n• Iron-rich foods\n• Vitamin D supplements\n\n<strong>Toddlers (1-3 years):</strong>\n• Balanced meals\n• Healthy snacks\n• Calcium for bone growth\n• Iron for brain development\n\n<strong>Children (4-12 years):</strong>\n• Variety of foods\n• Protein for growth\n• Whole grains\n• Fruits and vegetables\n\n<strong>Teenagers (13-18 years):</strong>\n• Increased calorie needs\n• Calcium for bone health\n• Iron for girls\n• Protein for muscle growth\n\n<strong>Healthy Eating Habits:</strong>\n• Family meals\n• Involve children in cooking\n• Limit sugary drinks\n• Avoid forced eating\n• Be a role model\n\n<strong>Common Concerns:</strong>\n• Picky eating\n• Food allergies\n• Obesity prevention\n• Eating disorders\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Laura Martinez', 'https://randomuser.me/api/portraits/women/8.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/4bUPl-qPg38/maxresdefault.jpg', 'https://www.youtube.com/watch?v=4bUPl-qPg38', '2024-06-05 10:00:00', '7 min read', 0, 0, 0, false, true, 'nutrition-for-children', NOW(), NOW()),

(31, 'Common Childhood Illnesses', 'Helps you recognize common childhood conditions and understand when to seek medical attention.', '<strong>Common Childhood Illnesses</strong>\n\nChildren are susceptible to various illnesses. This guide helps you recognize common childhood conditions and understand when to seek medical attention.\n\n<strong>Common Childhood Illnesses:</strong>\n\n<strong>Common Cold:</strong>\n• Runny nose\n• Cough\n• Slight fever\n• Treatment: Rest, fluids, saline drops\n\n<strong>Ear Infections:</strong>\n• Ear pain\n• Fever\n• Irritability\n• Treatment: Antibiotics if bacterial\n\n<strong>Stomach Flu (Gastroenteritis):</strong>\n• Vomiting\n• Diarrhea\n• Fever\n• Treatment: Hydration, rest\n\n<strong>Chickenpox:</strong>\n• Itchy rash\n• Fever\n• Fatigue\n• Treatment: Calamine lotion, rest\n\n<strong>Hand, Foot, and Mouth Disease:</strong>\n• Mouth sores\n• Rash on hands and feet\n• Fever\n• Treatment: Pain relief, hydration\n\n<strong>When to See a Doctor:</strong>\n• High fever\n• Difficulty breathing\n• Dehydration signs\n• Persistent vomiting\n• Unusual behavior\n\n<strong>Prevention:</strong>\n• Good handwashing\n• Vaccinations\n• Healthy diet\n• Adequate sleep\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Michael Chen', 'https://randomuser.me/api/portraits/men/34.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/hcoJm6exhbc/maxresdefault.jpg', 'https://www.youtube.com/watch?v=hcoJm6exhbc', '2024-06-10 10:00:00', '6 min read', 0, 0, 0, true, true, 'common-childhood-illnesses', NOW(), NOW()),

(32, 'Child Development Milestones', 'Helps you understand what to expect at each developmental stage and when to seek professional advice.', '<strong>Child Development Milestones</strong>\n\nChild development follows predictable patterns. This guide helps you understand what to expect at each developmental stage and when to seek professional advice.\n\n<strong>Developmental Milestones:</strong>\n\n<strong>0-3 Months:</strong>\n• Lifts head\n• Responds to sounds\n• Follows objects with eyes\n\n<strong>4-6 Months:</strong>\n• Rolls over\n• Reaches for objects\n• Babbles\n\n<strong>7-12 Months:</strong>\n• Sits without support\n• Crawls\n• Says first words\n\n<strong>1-2 Years:</strong>\n• Walks\n• Uses simple words\n• Points to objects\n\n<strong>2-3 Years:</strong>\n• Runs\n• Speaks in sentences\n• Follows simple instructions\n\n<strong>3-5 Years:</strong>\n• Hops and jumps\n• Tells stories\n• Recognizes colors and shapes\n\n<strong>When to Seek Help:</strong>\n• Not meeting milestones\n• Loss of skills\n• Persistent difficulties\n• Concerns about development\n\n<strong>Supporting Development:</strong>\n• Play and interaction\n• Reading daily\n• Encouraging exploration\n• Providing love and support\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'General Medicine', 'Dr. Michael Chen', 'https://randomuser.me/api/portraits/men/34.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/g4HdXxz25pw/maxresdefault.jpg', 'https://www.youtube.com/watch?v=g4HdXxz25pw', '2024-06-15 10:00:00', '7 min read', 0, 0, 0, false, true, 'child-development-milestones', NOW(), NOW());

-- PEDIATRICS (8 posts) - Dr. Jessica Park (33-34), Dr. Robert Kim (35-36), Dr. Laura Bennett (37-38), Dr. William Parker (39-40)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(33, 'Screen Time and Children Health', 'Provides guidelines for healthy screen time use and alternatives for children.', '<strong>Screen Time and Children Health</strong>\n\nExcessive screen time can affect children''s physical and mental health. This article provides guidelines for healthy screen time use and alternatives for children.\n\n<strong>Effects of Screen Time:</strong>\n• Sleep problems\n• Behavioral issues\n• Reduced physical activity\n• Eye strain\n• Social difficulties\n\n<strong>Screen Time Guidelines:</strong>\n• Under 18 months: No screen time except video calls\n• 18-24 months: Limited, high-quality content\n• 2-5 years: 1 hour per day\n• 6+ years: Consistent limits\n\n<strong>Creating Healthy Habits:</strong>\n• Establish screen-free zones (bedroom, dinner table)\n• Set screen time rules\n• Be a role model\n• Use parental controls\n\n<strong>Alternatives to Screens:</strong>\n• Outdoor play\n• Reading\n• Arts and crafts\n• Board games\n• Family activities\n\n<strong>Monitoring Screen Content:</strong>\n• Educational content\n• Age-appropriate programs\n• Avoid violence and inappropriate content\n• Watch with children when possible\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Jessica Park', 'https://randomuser.me/api/portraits/women/9.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/0pOQHQ6x-Y8/maxresdefault.jpg', 'https://www.youtube.com/watch?v=0pOQHQ6x-Y8', '2024-06-20 10:00:00', '6 min read', 0, 0, 0, false, true, 'screen-time-children', NOW(), NOW()),

(34, 'Emergency First Aid for Children', 'Essential first aid techniques for common childhood emergencies including choking, burns, and falls.', '<strong>Emergency First Aid for Children</strong>\n\nAccidents can happen anytime. Learn essential first aid techniques for common childhood emergencies including choking, burns, and falls.\n\n<strong>Common Emergencies:</strong>\n\n<strong>Choking:</strong>\n• Signs: Coughing, difficulty breathing\n• Infant: Back blows and chest thrusts\n• Child: Abdominal thrusts (Heimlich)\n• Call emergency if severe\n\n<strong>Burns:</strong>\n• Cool burn with running water\n• Cover with clean cloth\n• Do not apply ice\n• Seek medical help for severe burns\n\n<strong>Falls:</strong>\n• Check for serious injuries\n• Apply ice for swelling\n• Head injury: Watch for vomiting or drowsiness\n• Seek medical care for severe falls\n\n<strong>First Aid Kit:</strong>\n• Bandages\n• Antiseptic\n• Thermometer\n• Scissors\n• Tweezers\n• Emergency numbers\n\n<strong>When to Call Emergency:</strong>\n• Difficulty breathing\n• Unconsciousness\n• Severe bleeding\n• Suspected poisoning\n• Head injury with confusion\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Jessica Park', 'https://randomuser.me/api/portraits/women/9.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/vDYaYoyFkqU/maxresdefault.jpg', 'https://www.youtube.com/watch?v=vDYaYoyFkqU', '2024-06-25 10:00:00', '8 min read', 0, 0, 0, false, true, 'emergency-first-aid-children', NOW(), NOW()),

(35, 'Understanding Depression: Signs and Help', 'Helps you recognize the signs and find effective treatment and support.', '<strong>Understanding Depression: Signs and Help</strong>\n\nDepression is a serious mental health condition that affects millions. This guide helps you recognize the signs and find effective treatment and support.\n\n<strong>What is Depression?</strong>\nDepression is more than just feeling sad. It''s a medical condition that affects how you feel, think, and handle daily activities.\n\n<strong>Common Signs of Depression:</strong>\n• Persistent sadness or empty mood\n• Loss of interest in activities\n• Changes in appetite or weight\n• Sleep problems\n• Fatigue or loss of energy\n• Difficulty concentrating\n• Feelings of worthlessness\n• Thoughts of death or suicide\n\n<strong>Types of Depression:</strong>\n• Major Depressive Disorder\n• Persistent Depressive Disorder\n• Seasonal Affective Disorder\n• Postpartum Depression\n• Bipolar Disorder\n\n<strong>Treatment Options:</strong>\n• Psychotherapy (talk therapy)\n• Antidepressant medications\n• Lifestyle changes\n• Support groups\n• Combination of treatments\n\n<strong>When to Seek Help:</strong>\n• Symptoms lasting more than 2 weeks\n• Interfering with daily life\n• Thoughts of self-harm\n• Substance abuse\n\n<strong>Supporting Someone with Depression:</strong>\n• Listen without judgment\n• Encourage professional help\n• Offer practical support\n• Be patient and understanding\n• Take care of yourself too\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Robert Kim', 'https://randomuser.me/api/portraits/men/35.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/d7NPnvKFs2Y/maxresdefault.jpg', 'https://www.youtube.com/watch?v=d7NPnvKFs2Y', '2024-07-01 10:00:00', '10 min read', 0, 0, 0, true, true, 'understanding-depression', NOW(), NOW()),

(36, 'Anxiety Management Strategies', 'Learn evidence-based strategies for managing anxiety and improving your quality of life.', '<strong>Anxiety Management Strategies</strong>\n\nAnxiety disorders are common but manageable. Learn evidence-based strategies for managing anxiety and improving your quality of life.\n\n<strong>Understanding Anxiety:</strong>\nAnxiety is a normal response to stress, but when it becomes excessive and persistent, it can interfere with daily life.\n\n<strong>Types of Anxiety Disorders:</strong>\n• Generalized Anxiety Disorder (GAD)\n• Panic Disorder\n• Social Anxiety Disorder\n• Specific Phobias\n• Obsessive-Compulsive Disorder (OCD)\n\n<strong>Symptoms of Anxiety:</strong>\n• Excessive worry\n• Restlessness\n• Fatigue\n• Difficulty concentrating\n• Irritability\n• Muscle tension\n• Sleep problems\n• Panic attacks\n\n<strong>Management Strategies:</strong>\n\n<strong>Cognitive Behavioral Therapy (CBT):</strong>\n• Identify negative thought patterns\n• Challenge irrational beliefs\n• Develop coping strategies\n\n<strong>Relaxation Techniques:</strong>\n• Deep breathing exercises\n• Progressive muscle relaxation\n• Mindfulness meditation\n• Guided imagery\n\n<strong>Lifestyle Changes:</strong>\n• Regular exercise\n• Healthy diet\n• Adequate sleep\n• Limit caffeine and alcohol\n• Social connections\n\n<strong>Medication Options:</strong>\n• SSRIs\n• SNRIs\n• Benzodiazepines (short-term)\n• Buspirone\n\n<strong>Self-Help Strategies:</strong>\n• Journaling\n• Time management\n• Setting boundaries\n• Practicing self-care\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Robert Kim', 'https://randomuser.me/api/portraits/men/35.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/1XCObQjSHIs/maxresdefault.jpg', 'https://www.youtube.com/watch?v=1XCObQjSHIs', '2024-07-05 10:00:00', '9 min read', 0, 0, 0, false, true, 'anxiety-management', NOW(), NOW()),

(37, 'The Power of Mindfulness', 'Explains the science behind mindfulness and provides practical techniques for daily practice.', '<strong>The Power of Mindfulness</strong>\n\nMindfulness is a powerful tool for mental health. This article explains the science behind mindfulness and provides practical techniques for daily practice.\n\n<strong>What is Mindfulness?</strong>\nMindfulness is the practice of paying attention to the present moment without judgment. It involves being fully aware of your thoughts, feelings, and surroundings.\n\n<strong>Benefits of Mindfulness:</strong>\n• Reduces stress and anxiety\n• Improves focus and concentration\n• Enhances emotional regulation\n• Promotes better sleep\n• Increases self-awareness\n• Improves relationships\n• Reduces chronic pain\n\n<strong>Mindfulness Techniques:</strong>\n\n<strong>Mindful Breathing:</strong>\n• Focus on your breath\n• Notice the sensation of breathing\n• Bring attention back when distracted\n\n<strong>Body Scan:</strong>\n• Pay attention to each part of your body\n• Notice sensations without judgment\n• Release tension\n\n<strong>Mindful Eating:</strong>\n• Eat slowly without distractions\n• Notice flavors and textures\n• Appreciate your food\n\n<strong>Mindful Walking:</strong>\n• Focus on the sensation of walking\n• Notice your surroundings\n• Stay present in the moment\n\n<strong>How to Start a Mindfulness Practice:</strong>\n• Start with 5 minutes daily\n• Use guided meditations\n• Be patient with yourself\n• Practice consistently\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Laura Bennett', 'https://randomuser.me/api/portraits/women/23.jpg', 'https://images.unsplash.com/photo-1516534775068-ba3e7458af70?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/IeblJdB2-Vo/maxresdefault.jpg', 'https://www.youtube.com/watch?v=IeblJdB2-Vo', '2024-07-10 10:00:00', '7 min read', 0, 0, 0, false, true, 'power-of-mindfulness', NOW(), NOW()),

(38, 'Building Resilience in Children', 'Strategies for helping children develop resilience and navigate challenges effectively.', '<strong>Building Resilience in Children</strong>\n\nResilience is a crucial life skill. This guide provides strategies for helping children develop resilience and navigate challenges effectively.\n\n<strong>What is Resilience?</strong>\nResilience is the ability to bounce back from adversity, adapt to change, and cope with stress. It''s a skill that can be developed and strengthened.\n\n<strong>Why Resilience Matters:</strong>\n• Helps children handle setbacks\n• Builds confidence\n• Promotes mental health\n• Improves problem-solving skills\n• Strengthens relationships\n\n<strong>Strategies to Build Resilience:</strong>\n\n<strong>Foster Strong Connections:</strong>\n• Build supportive relationships\n• Encourage friendships\n• Create a sense of belonging\n\n<strong>Teach Coping Skills:</strong>\n• Problem-solving techniques\n• Emotional regulation\n• Stress management\n• Positive self-talk\n\n<strong>Encourage Independence:</strong>\n• Allow age-appropriate risks\n• Let children make decisions\n• Support problem-solving\n• Praise effort, not just results\n\n<strong>Model Resilience:</strong>\n• Demonstrate healthy coping\n• Talk about your own challenges\n• Show optimism\n• Practice self-care\n\n<strong>Create a Safe Environment:</strong>\n• Provide emotional support\n• Establish routines\n• Set clear expectations\n• Show unconditional love\n\n<strong>Signs of Resilience:</strong>\n• Ability to express emotions\n• Problem-solving skills\n• Positive outlook\n• Strong relationships\n• Adaptability\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. Laura Bennett', 'https://randomuser.me/api/portraits/women/23.jpg', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/akUHbUhe1-w/maxresdefault.jpg', 'https://www.youtube.com/watch?v=akUHbUhe1-w', '2024-07-15 10:00:00', '8 min read', 0, 0, 0, false, true, 'building-resilience', NOW(), NOW()),

(39, 'Mental Health at Work', 'Strategies for maintaining mental health, setting boundaries, and finding work-life balance.', '<strong>Mental Health at Work: Strategies for Wellbeing</strong>\n\nWorkplace stress is common. This article provides strategies for maintaining mental health, setting boundaries, and finding work-life balance.\n\n<strong>Understanding Workplace Mental Health:</strong>\nWorkplace mental health affects productivity, job satisfaction, and overall wellbeing. It''s important for both employees and employers to prioritize mental health.\n\n<strong>Common Workplace Challenges:</strong>\n• High workload\n• Tight deadlines\n• Poor work-life balance\n• Lack of autonomy\n• Conflict with colleagues\n• Job insecurity\n• Burnout\n\n<strong>Strategies for Mental Health at Work:</strong>\n\n<strong>Set Boundaries:</strong>\n• Define work hours\n• Take regular breaks\n• Avoid checking work emails after hours\n• Learn to say no\n\n<strong>Manage Stress:</strong>\n• Prioritize tasks\n• Use time management techniques\n• Practice deep breathing\n• Take mental health days\n\n<strong>Build Support Networks:</strong>\n• Connect with colleagues\n• Find a mentor\n• Join employee resource groups\n• Seek professional help if needed\n\n<strong>Practice Self-Care:</strong>\n• Healthy eating\n• Regular exercise\n• Adequate sleep\n• Hobbies and interests outside work\n\n<strong>When to Seek Help:</strong>\n• Persistent anxiety or depression\n• Physical symptoms of stress\n• Difficulty coping with work demands\n• Changes in sleep or appetite\n• Thoughts of self-harm\n\n<strong>Employer Responsibilities:</strong>\n• Create a supportive environment\n• Provide mental health resources\n• Offer flexible work options\n• Reduce stigma\n• Train managers on mental health\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. William Parker', 'https://randomuser.me/api/portraits/men/46.jpg', 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/G0XUimJbz44/maxresdefault.jpg', 'https://www.youtube.com/watch?v=G0XUimJbz44', '2024-07-20 10:00:00', '9 min read', 0, 0, 0, true, true, 'mental-health-at-work', NOW(), NOW()),

(40, 'Parenting and Mental Health', 'Practical tips for maintaining your well-being while caring for your children.', '<strong>Parenting and Mental Health: A Guide for Parents</strong>\n\nParenting can be challenging for mental health. This guide offers practical tips for maintaining your well-being while caring for your children.\n\n<strong>The Parenting Challenge:</strong>\nParenting is rewarding but can also be stressful. It''s important to prioritize your mental health to be the best parent you can be.\n\n<strong>Common Parenting Challenges:</strong>\n• Sleep deprivation\n• Financial stress\n• Work-life balance\n• Relationship strain\n• Guilt and self-doubt\n• Social isolation\n\n<strong>Strategies for Parent Mental Health:</strong>\n\n<strong>Self-Care:</strong>\n• Schedule time for yourself\n• Maintain hobbies\n• Exercise regularly\n• Get enough sleep\n• Eat well\n\n<strong>Build a Support System:</strong>\n• Connect with other parents\n• Ask for help when needed\n• Join parenting groups\n• Maintain adult relationships\n\n<strong>Manage Expectations:</strong>\n• Accept imperfection\n• Set realistic goals\n• Celebrate small wins\n• Let go of guilt\n\n<strong>Seek Professional Help:</strong>\n• Therapy for yourself\n• Couples counseling\n• Family therapy\n• Support groups\n\n<strong>Signs You Need Help:</strong>\n• Persistent sadness or anxiety\n• Overwhelming stress\n• Difficulty coping with daily tasks\n• Thoughts of harming yourself or others\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Pediatrics', 'Dr. William Parker', 'https://randomuser.me/api/portraits/men/46.jpg', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/cYegqUJFqtc/maxresdefault.jpg', 'https://www.youtube.com/watch?v=cYegqUJFqtc', '2024-07-25 10:00:00', '8 min read', 0, 0, 0, false, true, 'parenting-mental-health', NOW(), NOW());

-- WOMEN & MEN HEALTH (10 posts) - Dr. Priya Sharma (41-42), Dr. Elizabeth White (43-44), Dr. Maria Garcia (45-46), Dr. Lisa Martinez (47-48), Dr. James Taylor (49-50)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(41, 'Women Health: A Comprehensive Guide', 'Covers everything from reproductive health to menopause and beyond.', '<strong>Women Health: A Comprehensive Guide</strong>\n\nWomen''s health encompasses a wide range of issues. This comprehensive guide covers everything from reproductive health to menopause and beyond.\n\n<strong>Women''s Health at Every Age:</strong>\n\n<strong>Reproductive Health:</strong>\n• Menstrual health\n• Contraception options\n• Fertility awareness\n• Pregnancy and postpartum care\n• Menopause management\n\n<strong>Common Health Concerns:</strong>\n• Breast health\n• Heart disease\n• Osteoporosis\n• Autoimmune diseases\n• Mental health\n\n<strong>Screenings and Prevention:</strong>\n• Mammograms\n• Pap smears\n• Bone density scans\n• Blood pressure checks\n• Cholesterol tests\n\n<strong>Lifestyle for Women''s Health:</strong>\n• Balanced nutrition\n• Regular exercise\n• Stress management\n• Adequate sleep\n• Social connections\n\n<strong>When to See a Doctor:</strong>\n• Unusual symptoms\n• Changes in menstrual cycle\n• Breast changes\n• Pelvic pain\n• Menopause symptoms\n• Mental health concerns\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Women Health', 'Dr. Priya Sharma', 'https://randomuser.me/api/portraits/women/10.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/7bISLOxfSBA/maxresdefault.jpg', 'https://www.youtube.com/watch?v=7bISLOxfSBA', '2024-08-01 10:00:00', '10 min read', 0, 0, 0, true, true, 'women-health-guide', NOW(), NOW()),

(42, 'Menopause: What to Expect', 'Explains what to expect and provides strategies for managing symptoms.', '<strong>Menopause: What to Expect</strong>\n\nMenopause is a natural transition in a woman''s life. This guide explains what to expect and provides strategies for managing symptoms.\n\n<strong>Understanding Menopause:</strong>\nMenopause is the time when a woman''s menstrual periods stop permanently. It typically occurs between ages 45-55.\n\n<strong>Stages of Menopause:</strong>\n• Perimenopause: Transition phase\n• Menopause: 12 months without periods\n• Postmenopause: After menopause\n\n<strong>Common Symptoms:</strong>\n• Hot flashes\n• Night sweats\n• Sleep problems\n• Mood changes\n• Weight gain\n• Vaginal dryness\n• Decreased libido\n• Memory problems\n\n<strong>Managing Symptoms:</strong>\n\n<strong>Lifestyle Changes:</strong>\n• Dress in layers\n• Stay cool\n• Exercise regularly\n• Healthy diet\n• Stress management\n\n<strong>Medical Treatments:</strong>\n• Hormone replacement therapy (HRT)\n• Non-hormonal medications\n• Supplements\n• Alternative therapies\n\n<strong>Long-term Health Considerations:</strong>\n• Bone health\n• Heart health\n• Weight management\n• Regular screenings\n\n<strong>When to Seek Help:</strong>\n• Severe symptoms\n• Emotional distress\n• Concerns about health risks\n• Questions about treatment options\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Women Health', 'Dr. Priya Sharma', 'https://randomuser.me/api/portraits/women/10.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/Y8CvNSdUFuk/maxresdefault.jpg', 'https://www.youtube.com/watch?v=Y8CvNSdUFuk', '2024-08-05 10:00:00', '9 min read', 0, 0, 0, false, true, 'menopause-guide', NOW(), NOW()),

(43, 'Breast Health: Screening and Prevention', 'Covers screening recommendations, self-examination techniques, and prevention strategies.', '<strong>Breast Health: Screening and Prevention</strong>\n\nBreast health is a priority for women of all ages. This guide covers screening recommendations, self-examination techniques, and prevention strategies.\n\n<strong>Understanding Breast Health:</strong>\nBreast health involves maintaining the health of breast tissue and detecting any changes early.\n\n<strong>Breast Cancer Risk Factors:</strong>\n• Age\n• Family history\n• Genetic mutations\n• Hormonal factors\n• Lifestyle factors\n• Dense breast tissue\n\n<strong>Prevention Strategies:</strong>\n• Maintain healthy weight\n• Limit alcohol\n• Exercise regularly\n• Breastfeed if possible\n• Regular screenings\n\n<strong>Screening Recommendations:</strong>\n• Self-exams: Monthly\n• Clinical breast exams: Every 1-3 years\n• Mammograms: Every 1-2 years (starting at 40)\n• MRI: For high-risk individuals\n\n<strong>Self-Examination Tips:</strong>\n• Look for changes in size or shape\n• Check for lumps or thickening\n• Watch for skin changes\n• Note nipple discharge or inversion\n\n<strong>When to See a Doctor:</strong>\n• New lump or mass\n• Skin changes\n• Nipple changes\n• Pain\n• Breast cancer family history\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Women Health', 'Dr. Elizabeth White', 'https://randomuser.me/api/portraits/women/11.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/-sKrZgeII-o/maxresdefault.jpg', 'https://www.youtube.com/watch?v=-sKrZgeII-o', '2024-08-10 10:00:00', '8 min read', 0, 0, 0, false, true, 'breast-health-screening', NOW(), NOW()),

(44, 'Fertility and Reproductive Health', 'Covers common concerns, lifestyle factors, and when to seek help.', '<strong>Fertility and Reproductive Health</strong>\n\nFertility and reproductive health are important aspects of women''s health. This guide covers common concerns, lifestyle factors, and when to seek help.\n\n<strong>Understanding Fertility:</strong>\nFertility is the ability to conceive and carry a pregnancy. It involves both partners and many factors.\n\n<strong>Common Fertility Issues:</strong>\n• Ovulation disorders\n• Blocked fallopian tubes\n• Endometriosis\n• Uterine fibroids\n• Low sperm count\n• Age-related factors\n\n<strong>Lifestyle Factors Affecting Fertility:</strong>\n• Age\n• Weight\n• Smoking\n• Alcohol\n• Stress\n• Nutrition\n\n<strong>When to Seek Help:</strong>\n• Under 35: After 1 year of trying\n• Over 35: After 6 months\n• Known medical conditions\n• Irregular periods\n• Previous fertility issues\n\n<strong>Fertility Treatments:</strong>\n• Medications to stimulate ovulation\n• Intrauterine insemination (IUI)\n• In vitro fertilization (IVF)\n• Surgery\n• Donor eggs or sperm\n\n<strong>Reproductive Health Tips:</strong>\n• Regular gynecological check-ups\n• STI prevention\n• Healthy lifestyle\n• Manage chronic conditions\n• Stress management\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Women Health', 'Dr. Elizabeth White', 'https://randomuser.me/api/portraits/women/11.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/6gTERZLPSyI/maxresdefault.jpg', 'https://www.youtube.com/watch?v=6gTERZLPSyI', '2024-08-15 10:00:00', '9 min read', 0, 0, 0, false, true, 'fertility-reproductive-health', NOW(), NOW()),

(45, 'Pregnancy Wellness Guide', 'Essential tips for maintaining health during pregnancy and the postpartum period.', '<strong>Pregnancy Wellness Guide</strong>\n\nPregnancy is a journey that requires special care. This guide provides essential tips for maintaining health during pregnancy and the postpartum period.\n\n<strong>Prenatal Care:</strong>\nRegular check-ups are essential for monitoring both mother and baby''s health.\n\n<strong>First Trimester (Weeks 1-12):</strong>\n• Start prenatal vitamins\n• Manage morning sickness\n• Schedule first prenatal visit\n• Avoid harmful substances\n\n<strong>Second Trimester (Weeks 13-26):</strong>\n• Noticeable baby movement\n• Anatomy scan\n• Gestational diabetes screening\n• Preparing for baby\n\n<strong>Third Trimester (Weeks 27-40):</strong>\n• More frequent check-ups\n• Preparing for labor\n• Baby positioning\n• Final preparations\n\n<strong>Nutrition During Pregnancy:</strong>\n• Balanced diet\n• Adequate protein\n• Iron-rich foods\n• Calcium and vitamin D\n• Healthy fats\n• Hydration\n\n<strong>Exercise During Pregnancy:</strong>\n• Regular walking\n• Swimming\n• Prenatal yoga\n• Light strength training\n• Consult your doctor first\n\n<strong>Postpartum Care:</strong>\n• Physical recovery\n• Emotional health\n• Breastfeeding support\n• Sleep strategies\n• Pelvic floor exercises\n\n<strong>Warning Signs:</strong>\n• Severe bleeding\n• High fever\n• Severe headache\n• Vision changes\n• Decreased fetal movement\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Women Health', 'Dr. Maria Garcia', 'https://randomuser.me/api/portraits/women/12.jpg', 'https://images.unsplash.com/photo-1584820927498-cfe5211fd8bf?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/mlwo6TA6Tso/maxresdefault.jpg', 'https://www.youtube.com/watch?v=mlwo6TA6Tso', '2024-08-20 10:00:00', '10 min read', 0, 0, 0, true, true, 'pregnancy-wellness', NOW(), NOW()),

(46, 'Men Health: A Comprehensive Guide', 'Covers everything from heart health to prostate health and beyond.', '<strong>Men Health: A Comprehensive Guide</strong>\n\nMen''s health is often overlooked. This comprehensive guide covers everything from heart health to prostate health and beyond.\n\n<strong>Key Health Issues for Men:</strong>\n• Heart disease\n• Prostate cancer\n• Testicular cancer\n• Mental health\n• Erectile dysfunction\n• Diabetes\n\n<strong>Preventive Care:</strong>\n• Regular check-ups\n• Blood pressure screening\n• Cholesterol tests\n• Diabetes screening\n• Prostate exams\n• Testicular self-exams\n\n<strong>Lifestyle for Men''s Health:</strong>\n• Balanced nutrition\n• Regular exercise\n• Maintain healthy weight\n• Manage stress\n• Adequate sleep\n• Limit alcohol\n• Quit smoking\n\n<strong>When to See a Doctor:</strong>\n• Chest pain\n• Erectile changes\n• Urinary changes\n• Persistent fatigue\n• Mental health concerns\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Men Health', 'Dr. Maria Garcia', 'https://randomuser.me/api/portraits/women/12.jpg', 'https://images.unsplash.com/photo-1516069677018-3785c3c2c5c3?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/NlsYVnS35Fg/maxresdefault.jpg', 'https://www.youtube.com/watch?v=NlsYVnS35Fg', '2024-08-25 10:00:00', '8 min read', 0, 0, 0, false, true, 'men-health-guide', NOW(), NOW()),

(47, 'Prostate Health: Prevention and Treatment', 'Covers common conditions, prevention strategies, and treatment options.', '<strong>Prostate Health: Prevention and Treatment</strong>\n\nProstate health is a key concern for men as they age. This guide covers common conditions, prevention strategies, and treatment options.\n\n<strong>Understanding Prostate Health:</strong>\nThe prostate is a small gland in men that produces seminal fluid. It''s important for reproductive health.\n\n<strong>Common Prostate Conditions:</strong>\n• Benign prostatic hyperplasia (BPH)\n• Prostatitis\n• Prostate cancer\n\n<strong>Risk Factors:</strong>\n• Age (over 50)\n• Family history\n• Race (African American)\n• Diet high in fat\n• Sedentary lifestyle\n\n<strong>Symptoms of Prostate Issues:</strong>\n• Frequent urination\n• Urgency\n• Weak urine stream\n• Painful urination\n• Blood in urine\n• Erectile dysfunction\n\n<strong>Prevention Strategies:</strong>\n• Healthy diet\n• Regular exercise\n• Maintain healthy weight\n• Regular screening\n• Manage stress\n\n<strong>Screening Recommendations:</strong>\n• PSA test: Starting at 50\n• Digital rectal exam\n• Discuss with your doctor\n\n<strong>Treatment Options:</strong>\n• Watchful waiting\n• Medications\n• Surgery\n• Radiation therapy\n• Lifestyle changes\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Men Health', 'Dr. Lisa Martinez', 'https://randomuser.me/api/portraits/women/13.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/poTcAm_rknw/maxresdefault.jpg', 'https://www.youtube.com/watch?v=poTcAm_rknw', '2024-09-01 10:00:00', '9 min read', 0, 0, 0, false, true, 'prostate-health', NOW(), NOW()),

(48, 'Testosterone and Men Health', 'Covers the importance of testosterone, signs of deficiency, and treatment options.', '<strong>Testosterone and Men Health</strong>\n\nTestosterone plays a crucial role in men''s health. This article covers the importance of testosterone, signs of deficiency, and treatment options.\n\n<strong>What is Testosterone?</strong>\nTestosterone is the primary male sex hormone. It''s responsible for male characteristics and plays a role in many bodily functions.\n\n<strong>Functions of Testosterone:</strong>\n• Sexual development\n• Muscle mass\n• Bone density\n• Fat distribution\n• Red blood cell production\n• Mood and energy\n\n<strong>Signs of Low Testosterone:</strong>\n• Fatigue\n• Decreased sex drive\n• Erectile dysfunction\n• Mood changes\n• Weight gain\n• Reduced muscle mass\n• Sleep problems\n\n<strong>Causes of Low Testosterone:</strong>\n• Aging\n• Injury to testicles\n• Chronic health conditions\n• Obesity\n• Medications\n\n<strong>Treatment Options:</strong>\n• Testosterone replacement therapy\n• Lifestyle changes\n• Weight loss\n• Exercise\n• Dietary improvements\n\n<strong>Risks of Testosterone Therapy:</strong>\n• Blood clots\n• Sleep apnea\n• Acne\n• Breast enlargement\n• Discuss with your doctor\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Men Health', 'Dr. Lisa Martinez', 'https://randomuser.me/api/portraits/women/13.jpg', 'https://images.unsplash.com/photo-1505751172876-fa5323c4e7b1?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/GRxb6-CyPxM/maxresdefault.jpg', 'https://www.youtube.com/watch?v=GRxb6-CyPxM', '2024-09-05 10:00:00', '8 min read', 0, 0, 0, false, true, 'testosterone-men-health', NOW(), NOW()),

(49, 'Cardiovascular Health for Men', 'Provides heart health tips and strategies for prevention.', '<strong>Cardiovascular Health for Men</strong>\n\nHeart disease is a leading cause of death in men. This guide provides heart health tips and strategies for prevention.\n\n<strong>Heart Disease in Men:</strong>\nMen are at higher risk for heart disease than women, often at a younger age.\n\n<strong>Risk Factors for Men:</strong>\n• Age\n• Family history\n• High blood pressure\n• High cholesterol\n• Diabetes\n• Smoking\n• Obesity\n• Physical inactivity\n\n<strong>Prevention Strategies:</strong>\n• Regular exercise (150 minutes/week)\n• Heart-healthy diet\n• Maintain healthy weight\n• Quit smoking\n• Limit alcohol\n• Manage stress\n\n<strong>Warning Signs of Heart Attack:</strong>\n• Chest pain\n• Pain radiating to arm\n• Shortness of breath\n• Nausea\n• Cold sweat\n\n<strong>Lifestyle Changes:</strong>\n• Healthy eating plan\n• Regular physical activity\n• Weight management\n• Stress reduction\n• Adequate sleep\n\n<strong>Medical Management:</strong>\n• Regular check-ups\n• Blood pressure monitoring\n• Cholesterol management\n• Diabetes control\n• Medications as prescribed\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Men Health', 'Dr. James Taylor', 'https://randomuser.me/api/portraits/men/36.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/GjXW3Tgiz4A/maxresdefault.jpg', 'https://www.youtube.com/watch?v=GjXW3Tgiz4A', '2024-09-10 10:00:00', '7 min read', 0, 0, 0, true, true, 'cardiovascular-health-men', NOW(), NOW()),

(50, 'Mental Health for Men', 'Addresses common mental health concerns and provides resources for support.', '<strong>Mental Health for Men: Breaking the Stigma</strong>\n\nMental health is often overlooked in men. This guide addresses common mental health concerns and provides resources for support.\n\n<strong>Why Men''s Mental Health Matters:</strong>\nMen are less likely to seek help for mental health issues due to stigma and societal expectations.\n\n<strong>Common Mental Health Issues in Men:</strong>\n• Depression\n• Anxiety\n• Stress\n• Burnout\n• Substance abuse\n• Anger issues\n\n<strong>Barriers to Seeking Help:</strong>\n• Stigma\n• Difficulty expressing emotions\n• Focus on physical health\n• Work and family demands\n\n<strong>Warning Signs:</strong>\n• Irritability\n• Withdrawal\n• Physical symptoms\n• Changes in sleep\n• Risky behavior\n\n<strong>Strategies for Mental Health:</strong>\n• Talk to someone\n• Professional help\n• Self-care\n• Stress management\n• Healthy lifestyle\n\n<strong>When to Seek Help:</strong>\n• Persistent sadness\n• Feeling overwhelmed\n• Thoughts of self-harm\n• Substance abuse\n• Relationship issues\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Men Health', 'Dr. James Taylor', 'https://randomuser.me/api/portraits/men/36.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/DJZdmNkgjxU/maxresdefault.jpg', 'https://www.youtube.com/watch?v=DJZdmNkgjxU', '2024-09-15 10:00:00', '8 min read', 0, 0, 0, false, true, 'mental-health-men', NOW(), NOW());

-- LIFESTYLE & WELLNESS (6 posts) - Dr. Katherine Wright (51-52), Dr. David Kim (53-54), Dr. Brian Thompson (55-56)
INSERT INTO blog_posts (id, title, excerpt, content, category, author, author_image, image_url, thumbnail, video_url, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
(51, 'The Power of Yoga: Mind and Body Connection', 'Explores different yoga styles and their benefits for mind and body.', '<strong>The Power of Yoga: Mind and Body Connection</strong>\n\nYoga offers numerous health benefits for both mind and body. This guide explores different yoga styles and their benefits.\n\n<strong>What is Yoga?</strong>\nYoga is an ancient practice that combines physical postures, breathing techniques, and meditation to improve overall health.\n\n<strong>Benefits of Yoga:</strong>\n• Reduces stress and anxiety\n• Improves flexibility and strength\n• Enhances balance\n• Boosts immune function\n• Improves sleep\n• Supports mental clarity\n• Promotes relaxation\n\n<strong>Types of Yoga:</strong>\n• Hatha Yoga: Gentle, beginner-friendly\n• Vinyasa Yoga: Flow-based, dynamic\n• Ashtanga Yoga: Structured, intense\n• Iyengar Yoga: Alignment-focused\n• Bikram Yoga: Hot yoga\n• Restorative Yoga: Relaxation-focused\n\n<strong>Basic Yoga Poses:</strong>\n• Mountain Pose (Tadasana)\n• Downward Dog (Adho Mukha Svanasana)\n• Warrior I (Virabhadrasana I)\n• Tree Pose (Vrksasana)\n• Child''s Pose (Balasana)\n• Corpse Pose (Savasana)\n\n<strong>Getting Started:</strong>\n• Start with beginner classes\n• Wear comfortable clothing\n• Use a yoga mat\n• Listen to your body\n• Be patient with yourself\n\n<strong>Yoga and Meditation:</strong>\n• Breathing exercises (Pranayama)\n• Mindfulness meditation\n• Body awareness\n• Relaxation techniques\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. Katherine Wright', 'https://randomuser.me/api/portraits/women/14.jpg', 'https://images.unsplash.com/photo-1516534775068-ba3e7458af70?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/FERryOkx9iw/maxresdefault.jpg', 'https://www.youtube.com/watch?v=FERryOkx9iw', '2024-09-20 10:00:00', '9 min read', 0, 0, 0, true, true, 'power-of-yoga', NOW(), NOW()),

(52, 'Meditation for Beginners', 'A beginner''s guide with simple techniques to start your meditation practice.', '<strong>Meditation for Beginners: A Step-by-Step Guide</strong>\n\nMeditation can reduce stress and improve well-being. This beginner''s guide provides simple techniques to start your meditation practice.\n\n<strong>What is Meditation?</strong>\nMeditation is a practice where an individual uses a technique to focus the mind on a particular object, thought, or activity to achieve a mentally clear and emotionally calm state.\n\n<strong>Benefits of Meditation:</strong>\n• Reduces stress\n• Improves focus and concentration\n• Enhances self-awareness\n• Promotes emotional health\n• Improves sleep\n• Reduces pain\n\n<strong>Getting Started:</strong>\n• Find a quiet space\n• Sit comfortably\n• Set a timer (start with 5 minutes)\n• Close your eyes\n• Focus on your breath\n\n<strong>Meditation Techniques:</strong>\n\n<strong>1. Breath Awareness:</strong>\n• Focus on your breathing\n• Notice the sensation of air entering and leaving\n• When distracted, return to your breath\n\n<strong>2. Body Scan:</strong>\n• Pay attention to each part of your body\n• Start from toes to head\n• Notice sensations without judgment\n\n<strong>3. Loving-Kindness Meditation:</strong>\n• Send wishes for happiness to yourself\n• Extend to loved ones\n• Extend to all beings\n\n<strong>4. Walking Meditation:</strong>\n• Focus on the sensation of walking\n• Notice your steps\n• Be present in the moment\n\n<strong>Tips for Success:</strong>\n• Start small\n• Be consistent\n• Don''t judge your practice\n• Use guided meditations\n• Find what works for you\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. Katherine Wright', 'https://randomuser.me/api/portraits/women/14.jpg', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/Hzi3PDz1AWU/maxresdefault.jpg', 'https://www.youtube.com/watch?v=Hzi3PDz1AWU', '2024-09-25 10:00:00', '8 min read', 0, 0, 0, false, true, 'meditation-beginners', NOW(), NOW()),

(53, 'Work-Life Balance: A Guide', 'Practical strategies for achieving balance and preventing burnout.', '<strong>Work-Life Balance: A Guide to Wellbeing</strong>\n\nWork-life balance is essential for health and happiness. This guide provides practical strategies for achieving balance and preventing burnout.\n\n<strong>What is Work-Life Balance?</strong>\nWork-life balance is the ability to prioritize and manage both professional and personal responsibilities without experiencing excessive stress.\n\n<strong>Signs of Poor Work-Life Balance:</strong>\n• Constant fatigue\n• Lack of time for self-care\n• Neglecting relationships\n• Difficulty disconnecting from work\n• Feeling overwhelmed\n• Health issues\n\n<strong>Strategies for Better Balance:</strong>\n\n<strong>Set Boundaries:</strong>\n• Define work hours\n• Create a dedicated workspace\n• Learn to say no\n• Limit work notifications\n\n<strong>Time Management:</strong>\n• Prioritize tasks\n• Use productivity techniques\n• Take regular breaks\n• Delegate when possible\n\n<strong>Self-Care:</strong>\n• Regular exercise\n• Adequate sleep\n• Healthy eating\n• Hobbies and interests\n• Social connections\n\n<strong>Workplace Strategies:</strong>\n• Communicate with your manager\n• Use flexible work options\n• Take vacation time\n• Build support networks\n\n<strong>When to Seek Help:</strong>\n• Persistent burnout\n• Health symptoms\n• Relationship issues\n• Mental health concerns\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. David Kim', 'https://randomuser.me/api/portraits/men/37.jpg', 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/SiYG3Pgy4x8/maxresdefault.jpg', 'https://www.youtube.com/watch?v=SiYG3Pgy4x8', '2024-10-01 10:00:00', '9 min read', 0, 0, 0, false, true, 'work-life-balance', NOW(), NOW()),

(54, 'Healthy Aging Tips', 'Strategies for maintaining physical and mental health in your later years.', '<strong>Healthy Aging Tips: Strategies for a Long and Active Life</strong>\n\nAging is inevitable, but you can age healthily. This guide provides strategies for maintaining physical and mental health in your later years.\n\n<strong>Understanding Healthy Aging:</strong>\nHealthy aging involves maintaining physical, mental, and social well-being as you grow older.\n\n<strong>Physical Health Strategies:</strong>\n\n<strong>Regular Exercise:</strong>\n• Aerobic activity (walking, swimming)\n• Strength training (2-3 times/week)\n• Balance exercises (Tai Chi, yoga)\n• Flexibility (stretching)\n\n<strong>Healthy Nutrition:</strong>\n• Balanced diet\n• Adequate protein (maintain muscle)\n• Calcium and vitamin D\n• Fiber-rich foods\n• Hydration\n\n<strong>Preventive Care:</strong>\n• Regular check-ups\n• Screenings (blood pressure, cholesterol)\n• Vaccinations (flu, shingles)\n• Dental and vision care\n\n<strong>Mental Health Strategies:</strong>\n\n<strong>Cognitive Stimulation:</strong>\n• Reading\n• Puzzles and games\n• Learning new skills\n• Social engagement\n\n<strong>Social Connections:</strong>\n• Maintain relationships\n• Join groups and clubs\n• Volunteer\n• Community involvement\n\n<strong>Stress Management:</strong>\n• Relaxation techniques\n• Mindfulness\n• Hobbies and interests\n• Work-life balance\n\n<strong>Lifestyle Factors:</strong>\n• Quit smoking\n• Limit alcohol\n• Maintain healthy weight\n• Adequate sleep\n• Manage chronic conditions\n\n<strong>Common Age-Related Conditions:</strong>\n• Heart disease\n• Arthritis\n• Osteoporosis\n• Diabetes\n• Cognitive decline\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. David Kim', 'https://randomuser.me/api/portraits/men/37.jpg', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/qSt8aKtpDCA/maxresdefault.jpg', 'https://www.youtube.com/watch?v=qSt8aKtpDCA', '2024-10-05 10:00:00', '10 min read', 0, 0, 0, false, true, 'healthy-aging-tips', NOW(), NOW()),

(55, 'Digital Detox: Reclaiming Your Life', 'Explores the benefits of a digital detox and provides strategies for reducing screen time.', '<strong>Digital Detox: Reclaiming Your Life</strong>\n\nDigital overload is affecting mental health. This article explores the benefits of a digital detox and provides strategies for reducing screen time.\n\n<strong>What is Digital Detox?</strong>\nA digital detox is a period of time during which a person refrains from using electronic devices, particularly smartphones and computers.\n\n<strong>Signs You Need a Digital Detox:</strong>\n• Constant phone checking\n• Sleep problems\n• Eye strain\n• Reduced attention span\n• Anxiety without your phone\n• Neglecting relationships\n\n<strong>Benefits of Digital Detox:</strong>\n• Improved sleep\n• Better focus\n• Reduced stress\n• Enhanced relationships\n• More time for hobbies\n• Increased productivity\n\n<strong>Strategies for Digital Detox:</strong>\n\n<strong>Set Boundaries:</strong>\n• No phones during meals\n• Phone-free times during the day\n• No screens before bed\n• Social media limits\n\n<strong>Create Tech-Free Zones:</strong>\n• Bedroom\n• Dining area\n• Living room during family time\n\n<strong>Alternative Activities:</strong>\n• Reading\n• Nature walks\n• Face-to-face conversations\n• Hobbies\n• Exercise\n\n<strong>Use Technology Mindfully:</strong>\n• Disable unnecessary notifications\n• Use screen time tracking\n• Take regular breaks\n• Practice digital minimalism\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. Brian Thompson', 'https://randomuser.me/api/portraits/men/38.jpg', 'https://images.unsplash.com/photo-1582750433449-648ed127bb54?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/dtNgX56fXck/maxresdefault.jpg', 'https://www.youtube.com/watch?v=dtNgX56fXck', '2024-10-10 10:00:00', '7 min read', 0, 0, 0, false, true, 'digital-detox', NOW(), NOW()),

(56, 'Hydration: The Essential Guide', 'Explains why water matters and provides practical tips for staying hydrated.', '<strong>Hydration: The Essential Guide</strong>\n\nProper hydration is essential for health. This guide explains why water matters and provides practical tips for staying hydrated.\n\n<strong>Why Hydration Matters:</strong>\nWater is essential for every cell, tissue, and organ in your body. It helps regulate body temperature, transport nutrients, and remove waste.\n\n<strong>Benefits of Proper Hydration:</strong>\n• Maintains body temperature\n• Lubricates joints\n• Protects organs and tissues\n• Promotes healthy skin\n• Supports digestion\n• Prevents kidney stones\n\n<strong>How Much Water Do You Need?</strong>\n• Adults: 2-3 liters per day\n• Children: 1-2 liters per day\n• More during exercise or hot weather\n\n<strong>Signs of Dehydration:</strong>\n• Thirst\n• Dark urine\n• Dry mouth\n• Fatigue\n• Dizziness\n• Headache\n\n<strong>Tips for Staying Hydrated:</strong>\n• Carry a water bottle\n• Set reminders\n• Drink water before meals\n• Eat water-rich foods\n• Limit caffeinated drinks\n\n<strong>Hydration and Exercise:</strong>\n• Drink water before, during, and after exercise\n• Replace electrolytes lost through sweat\n• Monitor urine color as a guide\n\n<strong>Debunking Hydration Myths:</strong>\n• You don''t need to drink 8 glasses a day (need varies)\n• Caffeine in moderation doesn''t dehydrate\n• Thirst is not the only sign of dehydration\n\n<em>This information is for educational purposes. Always consult with your healthcare provider for medical advice.</em>', 'Lifestyle & Wellness', 'Dr. Brian Thompson', 'https://randomuser.me/api/portraits/men/38.jpg', 'https://images.unsplash.com/photo-1517824806704-9040b0377036?w=800&h=500&fit=crop&q=80', 'https://img.youtube.com/vi/F6XbT6rK4ME/maxresdefault.jpg', 'https://www.youtube.com/watch?v=F6XbT6rK4ME', '2024-10-15 10:00:00', '6 min read', 0, 0, 0, false, true, 'hydration-guide', NOW(), NOW());

